export const PAGES: LandingPage[] = [{ "slug": "airsaas-et-les-experts-de-la-transfo", "type": "solution", "meta": { "title": "Airsaas permet à un expert de la transfo. d'incarner un changement organisationnel", "description": "Rejoindre les dizaines d'experts de la Transfo. qui utilisent Airsaas pour piloter les transformations dans leurs missions.", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Surdélivrer vos missions avec AirSaas", "subtitle": "AirSaas c'est la solution la plus simple pour partager en continu une vue macro d'un projet transverse, d'un programme ou d’un portefeuille projet et mettre l'impact chez vos client au coeur de votre stratégie.Êtes-vous prêt à construire la bonne gouvernance pour vos missions ? Vous pouvez aligner vos donneurs d'ordres et vos parties prenantes sans effort et vous concentrer sur l'essentiel : dépasser les attentes de vos clients sur le delivery.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/668566e02bd789b8eb53e8fd_Register%20illustration.webp", "imageAlt": "AirSaas celebration" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "feature-split", "reversed": false, "title": "Se former entre experts, par des pairs", "body": "Dans un format de bootcamp hybride en 4 semaines, participez à 6 masterclass et obtenez les postures et tactiques pour faire d'AirSaas un catalyseur de transformation.<br/>‍<br/>Les deux dernières masterclass en présentiel à Paris sont suivies par les désormais réputés Bal de Promo. <br/><br/>ESN, cabinets de conseils, des bootcamps sur mesure pour vos équipes sont possibles.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65f8389fb184b54765f33b8d_1.webp", "imageAlt": "BootCamp" }, { "type": "feature-split", "reversed": true, "title": "AirSaas dans le tooling des missions", "body": "Chaque mission pour accompagner des clients à repenser leur Target Operating Model. <br/>Outillés avec AirSaas, vous imprimez une nouvelle donne chez vos clients et vous prouvez qu'en structurant la gouvernance d'un projet, d'un programme et en simplifiant le reporting, vous vous concentrez sur l'essentiel : la qualité du delivery.<br/>Airsaas vous fournit sa solution PPM et vous pouvez l'utiliser pour vos clients grâce mode multi-workspace.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65f84d82c72005c3ac0b0ef7_AirSaas%20Tools.webp", "imageAlt": "AirSaas : people + process + tool" }, { "type": "feature-split", "reversed": false, "title": "You never walk alone", "body": "AirSaas est une entreprise étendue et on partage avec sa Communauté des Pro. de la Transfo. un fit culturel, beaucoup de Co-Business et des events toute l'année.<br/>‍<br/>Nous accueillons de nouveaux membres cooptés ou après un premier échange sur nos attentes et engagements respectifs.<br/><br/>Partenaires, cette communauté de 200+ experts vous intéresse ?", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65eecd3466cd11301a067e06_logotype-LPDT_white-horizontal.svg", "imageAlt": "LPDT" }] }, { "slug": "flash-report", "type": "solution", "meta": { "title": "AirSaas : la solution de flash report automatisée pour les DSI et PMO", "description": "Automatisez votre flash report personnalisé, et facilitez la prise de décision en Copil. Finies les heures passées sur PowerPoint pour vos reportings projets !", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "La solution de‍flash report automatisée préférée des DSI et PMO", "subtitle": "Parce que vous avez plus à apporter à la transformation de votre entreprise que des PowerPoints chronophages, AirSaas automatise vos reportings projets et fluidifie la prise de décision en Copil.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Plus qu’une solution de reporting flash : une solution de gouvernance projet complète", "body": "<p>En du flash report automatisé, les autres fonctionnalités AirSaas vous font changer votre manière de gouverner votre portefeuille projet.<br/></p>" }, { "type": "intro", "title": "Les bonnes pratiques de flash report qui mènent vos projets plus loin, plus vite", "body": "<p>Un bon rapport flash, c’est bien. Mais y associer les bonnes pratiques de gouvernance projet, c’est mieux ! Pensez à appliquer ces trois conseils pour en faire un outil-clé de la transformation de votre entreprise.<br/></p>" }, { "type": "feature-split", "reversed": false, "title": "Toutes vos données consolidées en un seul clic", "body": "Vous passez un temps fou à chercher les informations à droite et à gauche, auprès de vos chefs de projets et sur vos outils de gestion de tâche ? Cette époque est révolue ! <br/><br/>AirSaas vous permet d’observer toutes les données relatives à votre portfolio de projets, consolidées et mises à jour en temps réel. La data est homogénéisée, et reportée automatiquement dans votre flash report - le tout en un seul clic.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Des rapports qui facilitent la prise de décision", "body": "La structure de votre flash report AirSaas aide vos décisionnaires à visualiser rapidement le contexte de vos projets, ainsi que les décisions à prendre.<br/><br/>Après des slides d’introduction qui rappellent les grandes lignes de vos projets (tableau de bord, planning, timeline…), les membres du Copil visualisent tout ce dont ils ont besoin pour prendre leurs décisions en deux slides : jalons, statuts, risques et météos des projets, métriques d’avancée, gains attendus, ressources humaines et budgets impliqués…", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Une structure fixe, mais personnalisable", "body": "AirSaas crée automatiquement votre flash report au format .ppt ou .pdf, selon une structure ultra-lisible. Le design de votre présentation est personnalisable aux couleurs de votre entreprise.<br/><br/>Si besoin, customisez le contenu de votre reporting, en y ajoutant des métriques-clés supplémentaires, un récapitulatif des décisions à prendre, ou encore des précisions sur le planning de vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report" }, { "type": "feature-split", "reversed": true, "title": "Une roadmap collaborative de vos projets", "body": "Avec AirSaas, créez des vues filtrées pour visualiser les éléments-clés de vos différents projets à même la plateforme : points d’attention, retards, météos…<br/><br/>De quoi assurer un pilotage macro de vos projets, pour vous focaliser sur ce qui requiert une attention immédiate de vos équipes métiers et décideurs business.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "timeline projet" }, { "type": "feature-split", "reversed": false, "title": "Une vision Kanban qui simplifie votre gouvernance", "body": "Centralisez sur votre dashboard toutes les décisions prises et à prendre sur vos projets, sous un format aisément lisible par toutes vos parties prenantes.<br/><br/>Le but ? Fluidifier la prise de décision, en évitant les données parasites qui rallongent vos réunions.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Des fiches de cadrage de projet collaboratives", "body": "Remplissez vos fiches de cadrage de manière collaborative, et développez une culture projet homogène dans toute l’entreprise.<br/><br/>Avec AirSaas, vos chefs de projet montent en puissance, pour faire avancer plus vite la transformation de votre organisation.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Des intégrations natives pour faciliter la remontée d’informations", "body": "Toutes les informations cruciales provenant des outils de gestion de tâches (Jira, Asana…) sont centralisées sur AirSaas, pour éviter la déperdition d’informations.<br/><br/>Les informations d’avancement de vos projets sont diffusées automatiquement sur vos canaux de communication interne (Microsoft Teams), pour que chacun soit toujours au courant.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "Optimisation des ressources disponibles" }, { "type": "feature-split", "reversed": false, "title": "Mettez en valeur le ressenti de vos équipes", "body": "Inclure dans votre reporting les métriques d’avancée de vos projets ne suffit pas. Pour impliquer chacun de manière forte dans vos projets, mettez en avant dans vos présentations les points d’attention ou les succès rencontrés, selon ce que vous en dit votre équipe de pilotage, vos responsables de projet, voire vos utilisateurs finaux. Parce qu’ensemble, on avance plus loin.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a7bb239ce496a6f00ac37f_metier-it.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Définissez votre fréquence d’envoi de reporting", "body": "Faites de vos reportings un véritable rendez-vous pour toutes vos parties prenantes, en définissant une fréquence à laquelle vous envoyez vos rapports. La bonne pratique ? Un reporting mensuel bien ficelé, qui met tout le monde au diapason de l’avancée de la transformation de l’entreprise.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Envoyez vos reportings projets à l’avance", "body": "Envoyez à tous les membres du Copil votre reporting en amont de votre réunion, et utilisez-le comme support de présentation le jour J. Ainsi, tout le monde visualise les mêmes éléments, et les décisions se prennent plus rapidement.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "Pilotage de projet" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "flash-report-projet", "type": "solution", "meta": { "title": "l’outil de flash report projet automatisé favori des PMO et DSI", "description": "Automatisez votre flash report projet, gagnez une journée de travail par semaine, et rendez plus fluides et plus rapides vos prises de décision en Copil.", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "L’outil de flash report projet qui vous fait gagner en temps et en efficacité", "subtitle": "Grâce à AirSaas, automatisez vos flash reports projets, et rendez votre prise de décision plus fluide, plus rapide, tout en alignant les parties prenantes de la transformation de votre entreprise.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Plus qu’une solution de reporting flash : un outil PPM projet moderne et simplissime", "body": "<p>AirSaas, ce n’est pas seulement l’automatisation de votre flash report projet, mais aussi des fonctionnalités dont vous ne pourrez plus vous passer pour votre gouvernance projet.<br/></p>" }, { "type": "intro", "title": "3 règles d’or pour utiliser votre flash report projet à bon escient", "body": "<p>AirSaas vous simplifie la tâche sur vos reportings projets. Mais n’oubliez pas d’appliquer les règles d’or suivantes pour en tirer le meilleur parti possible !<br/></p>" }, { "type": "feature-split", "reversed": true, "title": "Votre flash report 100% automatisé", "body": "Sur AirSaas, vous pouvez observer toutes les données que vous souhaitez intégrer à vos reportings projets dans des <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-faire-un-bon-point-davancement-projet\">tableaux de bord consolidés</a>. <br/><br/>Finie la recherche d’information dans votre outil de gestion de tâche ou de gestion de projet ! Toute votre data est ici, homogénéisée, et automatiquement reportée dans votre flash report projet en un simple clic, au format .ppt ou .pdf.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d742defe0bf46502743b11_Flash%20report%20export%20modal.webp", "imageAlt": "Flash report" }, { "type": "feature-split", "reversed": false, "title": "Des intégrations natives pour éviter le report de données manuel", "body": "Sur la marketplace AirSaas, vous trouverez des intégrations natives à tous vos outils favoris, pour synchroniser les données qui s’y trouvent automatiquement et en temps réel.<br/><br/>Intégrations à vos outils de project management (Jira, ClickUp, Asana, Monday), de communication interne (Microsoft Teams) et de gestion de service client (Zendesk) : tout ce qu’il faut pour vous faire gagner encore plus de temps.<br/><br/>Profitez de la marketplace d’intégrations natives d’AirSaas, qui synchronise votre plateforme PPM à vos outils préférés : gestion de tâches (Jira, ClickUp, Asana, Monday), communication interne (Microsoft Teams) et logiciel de service client (Zendesk).", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives" }, { "type": "feature-split", "reversed": false, "title": "Une structure fixe hyper-lisible", "body": "La structure automatique de votre flash report est faite pour en simplifier la lecture pour les membres de votre Copil. Elle rappelle les grandes lignes de vos projets (timeline, indicateurs-clés, planning…), avant de détailler les éléments-clés à savoir sur vos projets les plus urgents.<br/><br/>Jalons, statuts, risques et <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-mettre-une-bonne-meteo-projet\">météos des projets</a>, métriques d’avancée, gains attendus, ressources humaines et budgets sollicités… Vous assurez le suivi des projets grâce à cette structure claire et détaillée à la fois.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "Jalons" }, { "type": "feature-split", "reversed": true, "title": "Une personnalisation pour coller à vos objectifs stratégiques", "body": "Parce que votre reporting doit ressembler à votre organisation, personnalisez-le aux couleurs de votre entreprise, selon votre charte graphique.<br/><br/>Besoin d’ajouter à votre flash report projet d’autres données ? Intégrez-y des métriques-clés supplémentaires sur l’avancement du projet, des précisions sur les plannings à venir, ou bien un récapitulatif des décisions qui doivent être prises.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report" }, { "type": "feature-split", "reversed": false, "title": "Votre reporting : l’allié pour vous aider dans vos décisions", "body": "Grâce au flash report d’AirSaas, chaque chef de projet, décisionnaire et sponsor est aligné autour d’un livrable qui facilite les décisions. Parce que piloter des projets nécessite une valeur partagée par tous : la collaboration, grâce à une vision claire et unifiée du portfolio.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "la prise de décision" }, { "type": "feature-split", "reversed": true, "title": "Un gain de temps précieux pour votre gouvernance projet", "body": "AirSaas fait gagner en moyenne une journée par semaine aux PMO et DSI qui s’en emparent. Focalisez-vous sur la vraie valeur que vous apportez : la gouvernance de votre portefeuille projet, et le coaching des métiers, pour que les projets avancent plus vite, plus loin.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7437ca9f8f8d31e9a639b_Programmes%20analytics.webp", "imageAlt": "Programs" }, { "type": "feature-split", "reversed": true, "title": "Une vue macro pour simplifier votre planification stratégique", "body": "Depuis AirSaas, visualisez en mode macro l’intégralité de votre portefeuille projet, et toutes les informations qui y sont liées : retards, météos, points d’attention, jalons…<br/><br/>Tout est à jour en temps réel et consolidé dans votre <em>roadmap</em> collaborative, pour assurer un pilotage optimal de votre portfolio, en fonction des urgences de vos équipes métiers et de vos décideurs business.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "timeline" }, { "type": "feature-split", "reversed": false, "title": "Des vues personnalisables sur votre portefeuille de projets", "body": "Si AirSaas n’est pas un outil de gestion de projets, il vous permet tout de même d’obtenir une visibilité plus précise sur vos projets, grâce à la vue liste, sur laquelle vous passez en revue l’avancée et les indicateurs de chaque projet.<br/><br/>Profitez également de la vue Kanban, qui vous permet d’analyser les états d’avancement de vos projets et leurs tendances générales, ainsi que de la vue timeline, sous forme de diagramme de Gantt, pour optimiser votre gestion des ressources et repérer les inter-dépendances de vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Portfolio projects kanban status" }, { "type": "feature-split", "reversed": true, "title": "Vos fiches de cadrage de projet collaboratives", "body": "Homogénéiser la culture projet de votre entreprise, et faites monter les chefs de projet en compétences, en leur proposant de remplir les fiches de cadrage de manière collaborative.<br/><br/>Grâce à AirSaas, vos projets partent sur le bon pied, pour être menés à bout, et aligner tout le monde sur une même méthodologie.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage de projet" }, { "type": "feature-split", "reversed": false, "title": "L’outil collaboratif idéal pour mieux communiquer", "body": "Paramétrez sur votre plateforme les notifications que vous voulez envoyer à vos équipes opérationnelles. <br/><br/>Un projet est à risque ? La période est terminée, et vous voulez en faire un bilan ? En quelques clics, envoyez ces messages-clés aisément, en les paramétrant à échéances fixes depuis AirSaas.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "People envolved" }, { "type": "feature-split", "reversed": false, "title": "Intégrez le ressenti de vos équipes à vos flash reports", "body": "Présenter les métriques d’avancée de vos projets dans votre reporting, c’est bien. Mais y mettre en valeur le ressenti de vos équipes et de vos utilisateurs finaux dedans, c’est mieux ! Ce faisant, vous impliquez toutes les parties prenantes dans vos projets, et pouvez mettre en lumière les succès et les points d’attention qui ressortent de leur propre expérience. Parce qu’ensemble, on avance plus loin.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a7bb239ce496a6f00ac37f_metier-it.svg", "imageAlt": "équipes" }, { "type": "feature-split", "reversed": true, "title": "Tenez-vous à une fréquence d’envoi de reporting fixe", "body": "Votre flash report doit devenir un vrai rendez-vous pour toutes vos parties prenantes. Définissez la fréquence à laquelle vous le leur envoyez - nous vous recommandons un reporting mensuel, pour que chacun sache à tout moment où les projets en sont.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "reporting fixe" }, { "type": "feature-split", "reversed": false, "title": "Envoyez vos reportings projets en amont du Copil", "body": "Un Copil, ça se prépare - et pas seulement par vous ! Le fait d’envoyer en amont de la réunion votre reporting à tous les membres de votre Copil leur permet de se familiariser avec les décisions à prendre avant le jour J. Résultat : vous gagnez du temps pendant la réunion, et tout le monde est aligné autour d’un support de présentation connu de tous.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "Envoyez vos reportings projets" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "gestion-portefeuille-projet", "type": "solution", "meta": { "title": "Gestion de portefeuille projet : l'outil qui simplifie tout", "description": "Besoin d'un outil de gestion de portefeuille projet simple et orienté valeur ? Airsaas est la solution de PPM moderne préférée des DSI et des directions générales", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "L'outil de gestion de portefeuille projet nouvelle génération", "subtitle": "La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les problèmes les plus fréquents en gestion de portefeuille de projets. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Avancez plus sereinement avec votre équipe" }, { "type": "intro", "title": "Une distinction à faire : différencier les outils de gestion de projet et de gestion de portefeuille de projet", "body": "<p>De nombreuses personnes assimilent les outils de gestion de projets aux outils de gestion de portefeuille de projet. Pourtant, ces deux types d’outils ne servent pas les mêmes objectifs. <br/>‍<br/>Mais alors quelle est la différence entre ces deux typologies de logiciels ?<br/></p>" }, { "type": "intro", "body": "<p>‍</p><p>A mesure qu’elle se développe, une société est amenée à mener de plus en plus de projets en même temps. Si une bonne communication et une organisation structurée peuvent suffire pour diriger quelques projets conjointement, il arrive forcément un moment où la mise en place d’outil de gestion d’un portefeuille de projets devient un allié incontournable pour garder une efficience opérationnelle.</p><p>Pour résumer, à quoi sert un outil de gestion d’un portefeuille de projets ?<br/>Il permet notamment :</p><ul><li>de hiérarchiser les différents projets en fonction de leur priorité</li><li>d’’assurer une visibilité optimale sur l’ensemble des projets et leurs étapes</li><li>d’impliquer tous les responsables de projets via l’assignation d’objectifs</li><li>de faciliter la mise en place d’une méthodologie collaborative sur les projets tout en brisant les silos entre services/directions</li></ul>" }, { "type": "intro", "title": "Rapide historique des outils de gestion de portefeuille de projets" }, { "type": "intro", "body": "<p>‍</p><p>Il faut tout de même remarquer que certains de ces outils avaient été développés pour répondre à ces deux besoins (Sciforma, Ganttic) et que Planview était même axé dès son origine sur la gestion d’un portefeuille de projets. <br/>‍<br/>Aujourd’hui, il est très rare de rencontrer un outil qui ne couvre pas les deux aspects simultanément. Cependant, si ces logiciels présentent des différences dans les fonctionnalités qu’ils proposent, c’est en partie dû à la problématique qu’ils visaient lors de leur élaboration initiale - mais c’est aussi en rapport avec la vision du pilotage de projets qu’ils soutiennent.</p>" }, { "type": "intro", "title": "Des visions différentes du pilotage de projet : l’exemple des DSI", "body": "<p>Une des raisons pour laquelle les logiciels de gestion de portefeuilles de projets ne proposent pas tous les mêmes fonctionnalités : cela dépend de la manière dont ils ont été pensés historiquement, mais c’est aussi une conséquence de la vision de la gestion de projets qu’ils défendent.<br/><br/>Mais pourquoi existe-il différentes visions de la gestion de projet dans les DSI ?<br/></p>" }, { "type": "intro", "body": "<p>‍</p><p>L’essor du digital a donc structurellement amené la DSI à se voir confier davantage de missions, de nature parfois très éloignée du simple maintien des systèmes d’information. Se voyant chargée de nouvelles responsabilités, les attentes de la DSI en matière d’outils de pilotage de portefeuille projets ont donc forcément changé.</p>" }, { "type": "intro", "subSections": [{ "title": "D’une DSI axée sur le contrôle des process à une DSI collaborant étroitement avec les métiers", "body": "<p>Les transformations décrites précédemment amènent forcément un changement dans la façon dont la DSI va interagir avec les collaborateurs de son entreprise. En effet, une DSI axée principalement sur des missions techniques aura plus tendance à essayer de garder sous contrôle le comportement des différents utilisateurs des systèmes d’informations. Alors qu’une DSI qui souhaite apporter de la valeur dans le coeur de métier de ses collaborateurs aura besoin de développer une relation plus étroite avec ces derniers : si elle veut être capable de les accompagner dans l’implémentation de nouvelles manières de travailler, il faut qu’elle puisse comprendre finement leurs besoins. <br/>‍<br/>Ainsi, en fonction de la mission que se donne la DSI, cette dernière n’aura pas besoin du même type d’outil de gestion de portefeuilles de projets.</p>" }] }, { "type": "intro", "body": "<p><br/>Pour opposer ces deux styles de DSI, on pourrait les représenter par des pyramides de Maslow :</p>" }, { "type": "intro", "title": "Des visions opposées de la gestion de portefeuille de projets qui amènent à la mise en place d’outils différents", "body": "<p>Une fois que l’on a compris que les outils de gestion de portefeuille de projets n’offrent pas tous les mêmes fonctionnalités, il faut s’interroger : quel est le type d’outil permettra d’atteindre les objectifs de sa DSI ?<br/></p>" }, { "type": "intro", "subSections": [{ "title": "Des outils de gestion de portefeuille de projets variés selon les besoins de sa DSI", "body": "<p>Bien sûr, il existe des outils de pilotage de portefeuille de projet plus ou moins complets, proposant des fonctionnalités variées comme :</p><ul><li>La gestion des ressources</li><li>Le contrôle budgétaire</li><li>La gestion des risques</li><li>L'animation des instances des différents projets</li></ul><ul><li>La centralisation de toutes les informations essentielles</li><li>Le pilotage de la rentabilité des projets</li><li>La construction d’une communication efficiente entre équipes</li></ul><p>Mais plus qu’une liste des fonctionnalités, on peut regrouper les outils de gestion de portefeuille de projet en différentes catégories.</p>" }] }, { "type": "intro", "body": "<p>A l’inverse, d’autres outils (notamment ceux en mode SaaS) proposent moins de fonctionnalités mais ont la capacité de s’intégrer aux outils déjà installés. Opter pour ce genre de solutions permet d’éviter les doublons, et surtout de réduire le coût de change de son outil : en effet, la montée en version d’un ERP complet est un projet complexe, chronophage et coûteux. <br/>‍<br/>Chacun de ces types d’outils correspond au point de vue que l’on porte sur le rôle que doit occuper la DSI dans son entreprise. Si elle opte pour la mise en place d’outils plus légers et moins complets, c’est qu’elle considère que sa mission n’est plus forcément de devoir répondre à tous les besoins qu’a et qu’aura son entreprise simultanément, mais plutôt d’être en capacité de s’adapter aux évolutions de cette dernière. Ainsi, ces outils étaient faciles à mettre en place et à changer, la DSI peut reste en capacité de répondre efficacement à une problématique spécifique en fonction des attentes de son entreprise.</p>" }, { "type": "intro", "body": "<p>Tout d’abord, il est bien plus facile de réussir à impliquer les métiers lorsqu’on leur propose un outil avec une interface intuitive : il est compliqué d’attendre des métiers un engagement fort, lorsque les équipes IT se contentent de les inviter à travailler sur des outils qui n’ont pas été pensés pour des profils business. Les outils de gestion de portefeuille de projets avec une bonne UX sont donc généralement une des options à privilégier pour un DSI souhaitant amener les équipes IT et business à collaborer ensemble de manière efficace.<br/><br/>L’autre avantage majeur se situe au niveau du taux d’adoption du logiciel de portefeuille de projets : les outils misant sur l’UX offrent une prise en main rapide et sans trop de friction aux métiers. C’est un point fort qui devrait être pris en compte par tout DSI qui souhaite impliquer davantage les métiers de son entreprise dans les projets IT.</p>" }, { "type": "intro", "subSections": [{ "title": "Choisir son outil en fonction des méthodes de travail déjà installées", "body": "<p>Tous les outils portent une méthodologie en eux. Ainsi, une des astuces pour optimiser le taux d’adoption d’un nouveau logiciel dans son entreprise est de porter son choix vers la mise en place d’un outil avec une méthodologie intrinsèque proche de celle de son entreprise : que ce soit au niveau des objectifs que l’on vise, des méthodes de travail déjà installées, ou encore de la vision que l’on a de la gestion d’un portefeuille de projets par la DSI. <br/>‍<br/>Il est donc indispensable de se questionner sur les pratiques existantes, pour choisir son outil de gestion d’un portefeuille de projets en fonction.</p>" }] }, { "type": "intro", "subSections": [{ "title": "L’interface utilisateur comme vecteur de changement de la culture d’une entreprise", "body": "<p>Il est bien sûr conseillé de porter son choix sur la mise en place d’outil qui porte une méthodologie assez proche des process déjà existants dans votre entreprise. Mais il faut aussi noter qu’un outil d’un portefeuille de projets peut aussi faciliter l’implémentation de nouvelles méthodes de travail, ainsi que la changement progressif de la culture de l’entreprise.<br/><br/>En effet, la culture d'une entreprise est le fruit du comportement qu'elle adopte face à un environnement particulier. Donc si l'on change l'environnement, notamment en changeant les logiciels utilisés, on change la culture ! <br/>S’il le choix d’un nouvel outil peut être un levier pour accompagner un changement de pratiques, il faut tout de même prendre garde à ce que cette transformation des équipes de travail soit aussi accompagnée par des décisions et des directives : proposer un nouvel outil ne peut pas suffire à bousculer les habitudes ancrées dans le quotidien d’une entreprise.</p>" }] }, { "type": "intro", "body": "<p>Pour résumer : choisissez un outil dont la méthodologie intrinsèque n’est pas trop éloignée de la réalité de votre entreprise ou, à défaut, de celle que vous souhaitez installer.<br/></p>" }, { "type": "intro", "title": "Où se situe AirSaas dans le spectre de tous ces outils de gestion de portefeuille de projets ?", "body": "<p>AirSaas est un outil de gestion de portefeuilles projets plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités clés dont une DSI a besoin pour assurer l’exécution de ses projets.<br/></p>" }, { "type": "intro", "subSections": [{ "title": "Un outil PPM intuitif et intégré à vos outils existant", "body": "<p><strong>Jira<br/></strong><br/>En s’intégrant à Jira, AirSaas vous permet d'obtenir automatiquement les données d’avancement des projets sur la plateforme. Cela vous permettra d’avoir une vue globale de l’ensemble des projets et de leurs états d’avancement sans efforts.</p>" }] }, { "type": "intro", "body": "<p><strong>Microsoft Teams<br/>‍</strong><br/>AirSaas est intégré à Microsoft Teams. Les informations les plus importantes sur les projets en cours seront envoyées automatiquement sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pourrez partager simplement l’avancée des projets avec l’ensemble de l’entreprise. <br/>Si vous utilisez d’autres solutions n’hésitez pas à nous le dire !</p>" }, { "type": "intro", "subSections": [{ "title": "Un outil PPM portant une méthodologie collaborative pour impliquer les métiers", "body": "<p>Nous avons poussé la logique collaborative jusqu’au bout : AirSaas propose un moteur de recherche de solutions (externes/internes) accessibles aux responsables métiers.<br/>Lorsqu’un métier a un besoin, il cherche déjà des solutions de son côté sans forcément prévenir la DSI qui peut même finir par se retrouver face à du Shadow IT. <br/>‍<br/>Notre idée ici est de donner une solution à la DSI pour encadrer ces pratiques et structurer leurs efforts de recherche de solutions, tout en leur faisant comprendre les contraintes techniques du SI.</p>" }] }, { "type": "intro", "body": "<p><strong>AirSaas</strong>est donc solution PPM légère, qui s’intègre à l’existant, et qui porte une méthodologie collaborative forte afin d’impliquer les métiers.<br/></p>" }, { "type": "feature-split", "reversed": false, "title": "Décidez de manière avisée en Copil grâce au tableau de bord", "body": "La stratégie de l’entreprise est claire, l’organe de gouvernance projet est en place, il faut maintenant mettre à disposition des indicateurs pertinents et à jour pour prioriser les projets en fonction des urgences, gains potentiels, ressources accessibles, etc.<br/><br/>La performance de votre Copil dépend de votre capacité à prendre les bonnes décisions dans les bons délais. AirSaas vous donne accès à un <a href=\"https://www.airsaas.io/fr/solution/revue-de-portefeuille\">tableau de bord de votre portefeuille projet</a>. Vous pouvez utiliser les filtres pour trouver les projets sur lesquels vous devez concentrer vos efforts.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Améliorez l’efficacité du reporting sur les projets en cours", "body": "L’importance d’un bon reporting n’est plus à prouver. Plus les dirigeants et le management de l’entreprise est au courant de l’avancée des différents projets, plus les frustrations diverses disparaissent. Le problème est que le processus de collecte des informations nécessaire à ce reporting est une tâche chronophage pour vos collaborateurs. <br/><br/>C’est pour cela que nous vous proposons le rapport flash automatique. Générez une présentation (.ppt, .pdf, url) en un clic, avec l’ensemble des données à jour mises en forme dans des slides aux couleurs de votre entreprise.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Optimisez les ressources humaines disponibles", "body": "Chaque vue du portefeuille de projets vous apporte des connaissances différentes. La timeline donne une vision d’ensemble des projets avec leurs jalons associés. Vous pouvez en un clin d’oeil appercevoir les dépassements, les dépendances, et les projets à mener en parallèle. <br/><br/>Envisagez différents scénarios en déplaçant les projets dans le temps et choissez la stratégie apportant le plus grand bénéfice. L’outil vous affichera des recommandations en fonction de différents facteurs (disponibilité des ressources, importance du projet, retard sur des jalons importants, etc.)", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Optimisation des ressources disponibles" }, { "type": "feature-split", "reversed": true, "title": "Observez la consommation de vos ressources et de votre budget", "body": "Le suivi des budgets et l’optimisation des ressources est clé dans le métier de DSI. C’est la combinaison à suivre en continu pour piloter ses activités.<br/><br/>AirSaas récupère les temps et budgets consommés grâce à ses connecteurs avec vos outils financiers et de gestion de projets. D’autre part, un module de déclaration est accessible pour avoir des informations à jour, consolidées et exportables.<br/>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd47790f0e45_outil3.svg", "imageAlt": "Pilotage budgétaire" }, { "type": "feature-split", "reversed": false, "title": "Diminuez la frustration entre les métiers et l’IT", "body": "Vos équipes se plaignent du manque d’engagement des métiers sur les projets demandés. Et du côté des métiers, la frustration se ressent sur les retards et la non-prise en compte de leurs demandes.<br/>‍<br/>AirSaas propose un structure commune à suivre pour la mise en place d’un projet. La vue dashboard permet une compréhension partagée des contraintes de développement et une prise de décision collégiale par l’organe de gouvernance. <br/><br/>L’outil place le collaboratif au premier plan et permet de faire remonter les problèmes rencontrés, les succès du parcours, partager les compte-rendus de réunions, etc. pour impliquer les équipes autour d’un intérêt commun.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Vers un meilleur cadrage des projets", "body": "Une mauvaise définition du projet est souvent la première source de frustration des équipes IT, et toujours l'une des raisons principales de retard de livraison du projet. <br/><br/>Sur AirSaas, les utilisateurs sont accompagnés à se poser les bonnes questions et remplir les informations clés à un bon cadrage (gains espérés, critères de réussite, efforts à fournir, etc.). Ensuite, gardons en tête que le remplissage peut se faire de façon collaborative et asynchrone jusqu’au moment où le projet peut passer à l’état “prêt à valider” et être présenté au comité de pilotage.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4c030f0e65_Ameliorez-.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Des équipes plus engagées autour d’un objectif clair", "body": "Mesurer régulièrement le degré de confiance dans le succès du projet auprès des équipes est essentiel. Ainsi vous pourrez rectifier le tir avant que l’échec annoncé ne devienne trop coûteux pour l’entreprise. Sur AirSaas, vous pouvez envoyer un sondage à intervalle régulier, et ainsi améliorer l’engagement des équipes en écoutant leur préoccupations et en fluidifiant la collaboration entre les métiers et l’IT.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd1ad70f0e63_Partagez-.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Communiquez sur les avancées", "body": "Le contenu de votre plan de communication doit permettre aux responsables métiers et à votre direction de comprendre l’état d’avancement général, les points bloquants et les risques de glissement. Il doit aussi valoriser les succès pour motiver les équipes et inciter les récalcitrants à rejoindre le mouvement des projets qui réussissent. Le reporting est souvent considéré comme une activité chronophage. AirSaas vous aide dans ce processus en vous permettant de générer automatiquement vos rapports flash à envoyer en un clic.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd96500f0e62_Augmentez-.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "La gestion de projet", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fdab9a0f0e4a_outil8.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "La gestion d’un portefeuille de projets", "body": "Contrairement à l’outil de gestion de projet, la mise en place d’outil de gestion de portefeuille de projets permet d’optimiser l’exécution de plusieurs projets simultanément.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "La gestion d’un portefeuille de projets" }, { "type": "feature-split", "reversed": false, "title": "A quand remonte l’apparition des outils de gestion de portefeuilles de projets ?", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd6f640f0e4f_outil10.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Quelle était la première problématique ciblée : la gestion de projet ou la gestion de portefeuille de projets ?", "body": "En regardant ce graphique, on peut se rendre compte que plus de la moitié des outils de gestion de portefeuilles de projets ont en fait initialement été pensés pour répondre aux besoins de gestion de projet. Ce n’est qu’ensuite que ces derniers ont été complétés afin de couvrir les deux problématiques en même temps : la gestion de projet et la gestion de portefeuilles de projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd8da50f0e50_outil11.svg", "imageAlt": "Quel besoin est apparu en premier : la gestion de projet ou de portefeuille de projets ?" }, { "type": "feature-split", "reversed": false, "title": "La gestion de portefeuille : d’une mission centrée technique à une mission centrée business", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd42890f0e53_outil12.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "L’essor du digital : un vecteur de changement des besoins des DSI en gestion de portefeuille projets", "body": "L’avènement du digital offre la possibilité aux DSI d’accompagner leur entreprise différemment, et notamment en pesant davantage dans l’exécution des objectifs business. Une DSI qui digitalise les workflows des métiers leur apporte aujourd’hui énormément en simplifiant leur quotidien et en optimisant leur efficacité. La DSI peut même aider une entreprise à changer de business model en l’accompagnant dans la mise en place de nouveaux services en ligne. On peut aussi citer l’exemple que relate Pierre Raschi (DG de Référence DSI) : une boucherie a pu renouveler sa clientèle vieillissante grâce à l’intervention d’un DSI en temps partagé.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd08150f0e54_outil13.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Les outils de gestion de portefeuilles de projets all-in-one VS ceux qui s’intègrent aux outils existants", "body": "Certains outils de gestion de portefeuille de projets comme les ERP essayent de répondre à l’ensemble des besoins que peuvent avoir les DSI. S’ils sont souvent efficaces, il faut reconnaître qu’ils manquent toutefois de flexibilité une fois mis en place.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4a760f0e5b_outil15.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Les outils de gestion d’un portefeuille de projets avec un espace collaboratif structuré", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fda8f90f0e07_Qualifiez1b.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Les outils de gestion de portefeuille de projets qui misent sur l’UX", "body": "Les logiciels de gestion d’un portefeuille de projets qui ont été développés pour fournir une expérience utilisateur de haute qualité présentent deux avantages majeurs pour une DSI.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72e40db63dfa85954ccc5_Feed%20main.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Un outil PPM avec une UX forte", "body": "Notre pari : pour parvenir à impliquer les métiers, la DSI a besoin de l'<a href=\"/fr/solution/outil-ppm\">outil PPM</a> qu’ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n’est pas en forçant les métiers à travailler sur des logiciels complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70979f3aaee0cbfd859cc_Feed%20search%20solution.webp", "imageAlt": "Un outil PPM avec une UX forte" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "management-de-portefeuille-projet", "type": "solution", "meta": { "title": "Management de portefeuille projet : l'outil des DSI et PMO", "description": "Révolutionnez votre management de portefeuille de projet avec une solution PPM qui facilite la prise de décision et automatise vos reportings", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "L’outil de management de portefeuille projet qui révolutionne votre gouvernance", "subtitle": "AirSaas a été conçu pour vous aider à transformer votre entreprise de manière efficace, en vous faisant gagner en temps et en visibilité sur votre portfolio. Révolutionnez votre management de portefeuille de projet en gardant une vision précise de vos priorités, des décisions à prendre, et en communiquant mieux au quotidien.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Collaborez pour mieux transformer votre entreprise", "body": "<p>La gestion de votre portefeuille de projets nécessite une véritable collaboration entre vous, les métiers et les chefs de projet pour être optimale. Sur AirSaas, toutes les parties prenantes apportent leur pierre à l’édifice, depuis le cadrage des projets jusqu’à leur mise en œuvre quotidienne. Plus personne ne peut vous dire : “Je ne savais pas !”<br/></p>" }, { "type": "intro", "title": "Les 5 règles d’or d’un bon management de portefeuille projet", "body": "<p>Il ne suffit pas de déployer un bon outil de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/project-portfolio-management\">portfolio project management</a>pour assurer une gouvernance optimale à votre transformation d’entreprise. Suivez les cinq règles d’or suivantes pour structurer votre démarche, et décupler votre succès.<br/></p>" }, { "type": "feature-split", "reversed": true, "title": "Une planification stratégique simplifiée grâce à votre vue macro", "body": "AirSaas vous permet d’accéder à un tableau de bord de portefeuille projet simple à lire, où toutes vos informations-clés sont rassemblées, consolidées, et à jour en temps réel.<br/><br/>Prenez de la hauteur sur votre portfolio de projets avec votre vue macro, et prenez des décisions plus rapides, alignées avec les véritables priorités stratégiques de votre entreprise.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "planification stratégique" }, { "type": "feature-split", "reversed": false, "title": "Des intégrations natives pour limiter le report de données manuel", "body": "Profitez de la marketplace d’intégrations natives d’AirSaas, qui synchronise votre plateforme PPM à vos outils préférés : gestion de tâches (Jira, ClickUp, Asana, Monday), communication interne (Microsoft Teams) et logiciel de service client (Zendesk).<br/><br/>Vos tableaux de bord se mettent à jour automatiquement et en temps réel avec les données qui comptent.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives" }, { "type": "feature-split", "reversed": false, "title": "La vue liste", "body": "Besoin de suivre l’avancée de vos projets, et de leurs indicateurs-clés ? Rendez-vous sur la vue liste, et passez en revue les différents projets de votre portefeuille aisément.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "List" }, { "type": "feature-split", "reversed": true, "title": "La vue Kanban", "body": "Pour observer les tendances générales de votre portfolio, choisissez la vue Kanban, et analysez les états d’avancement de vos projets. Rien de tel pour optimiser votre stratégie de pilotage !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Kanban" }, { "type": "feature-split", "reversed": false, "title": "La vue timeline", "body": "Cette vue sous forme de diagramme de Gantt est idéale pour optimiser votre gestion des ressources, anticiper les retards, et repérer en amont les dépendances inter-projets. Vous organisez vos projets sur le temps long, pour ne plus rien laisser au hasard.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Timeline" }, { "type": "feature-split", "reversed": false, "title": "Votre reporting, véritable outil d’aide à la décision", "body": "Avec le flash report automatisé d’AirSaas, vous permettez à chacun de visualiser aisément les décisions qui doivent être prises à l’instant T. Décisionnaires, chefs d’équipe et de projets, sponsors : tout le monde est aligné, pour fluidifier la prise de décision.<br/><br/>Dans votre reporting, vous transmettez les grandes lignes de vos projets (planning, timeline, KPI…), puis vous rentrez dans le détail des projets urgents. Jalons, risques, météos des projets, KPI d’avancement, ressources humaines et budgets impliqués, gains attendus… Tout ce dont vous avez besoin est là.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "la prise de décision" }, { "type": "feature-split", "reversed": true, "title": "Une structure personnalisable et ultra-lisible", "body": "En un clic sur AirSaas, créez votre flash report au format .pdf ou .ppt, et personnalisez-en le design selon la charte de votre entreprise. Vous pouvez également y ajouter des métriques-clés supplémentaires, des précisions sur vos plannings, ou encore un récapitulatif exhaustif des décisions à prendre.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": true, "title": "Des fiches de cadrage co-créées", "body": "Impliquez chaque chef de projet dans le cadrage de vos projets, depuis la structure fixe AirSaas qui vous permet de définir un standard à votre culture projet. Cette méthodologie forte vous permet de faire démarrer chaque projet sur le bon pied.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage" }, { "type": "feature-split", "reversed": false, "title": "Une communication fluide avec tous les acteurs de votre transformation", "body": "Sur AirSaas, notifiez automatiquement vos équipes opérationnelles quand un projet est à risque, et envoyez des bilans aisément. Tout est paramétrable à échéances fixes, selon les rituels que vous avez créé dans votre management de portefeuille de projet.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Communiquez" }, { "type": "feature-split", "reversed": true, "title": "Des bilans de projet bien huilés", "body": "Rien de tel qu’un bilan de projet pour faire le point, et tirer les bonnes pratiques et les points d’amélioration de votre culture projet. Créez l’engagement de chacun en générant des bilans de projets complets : coûts, délais, retours DAKI et engagement de vos équipes s’y retrouvent - et tout le monde en tire les bonnes conclusions ---", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "bilans de projet" }, { "type": "feature-split", "reversed": false, "title": "Réduire la durée des projets dans votre portefeuille", "body": "Notre position : un projet ne devrait pas dépasser les trois mois. Les projets longs créent le chaos dans les équipes, qui perdent en engagement avec le temps - et bien souvent, ils ne voient jamais le jour.<br/><br/>Pour faire en sorte que chaque projet dure trois mois maximum, segmentez vos projets plus longs en plusieurs grandes phases de trois mois chacune. Ainsi, vous motivez toutes les parties prenantes, et vous assurez d’un pilotage des projets optimal.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659c49b1c11c7db42bdbe382_portfolio1-min.svg", "imageAlt": "indicateurs de performance" }, { "type": "feature-split", "reversed": true, "title": "Définir un ordre d’exécution des différents projets", "body": "Pour bien piloter votre portefeuille de projet, tout commence par une bonne définition des priorités à accorder à chacun de vos projets. Or, bien souvent, pour la direction, la plupart des projets sont hautement prioritaires : difficile alors de prioriser au quotidien dans votre gouvernance !<br/><br/>Pour pallier ce souci, définissez un ordre d’exécution des différents projets : lequel vient en premier, puis en deuxième, puis en troisième ?<br/><br/>Veillez également à éviter de toujours retenir l’avis de la personne la plus haut placée hiérarchiquement dans l’entreprise. Vous pouvez par exemple lui faire donner son avis en dernier lors des tours de table de votre comité de pilotage, pour pouvoir entendre tous les avis, et ne pas favoriser les projets d’une seule et même personne. ---", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d740ad0d75cbc3c06eba7f_Project%20page%20zoom%20importance-risk.webp", "imageAlt": "Project page importance-risk" }, { "type": "feature-split", "reversed": false, "title": "Privilégier l’achèvement de projets en cours que le lancement de nouveaux projets", "body": "Plus vous disposez de projets simultanés dans votre portefeuille, plus il est difficile de les finaliser rapidement. Ainsi, on observe <a href=\"https://www.airsaas.io/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet\">bon nombre d’entreprises lancer un grand nombre de projets</a>, sans jamais les voir s’achever. Privilégier un plus petit nombre de projets à la fois vous permet d’en observer plus rapidement la valeur générée.<br/><br/>Cette règle d’or demande donc de bien savoir prioriser les projets à lancer en premier. Focalisez-vous sur ceux qui apporteront en premier une véritable valeur ajoutée à votre organisation. Une réflexion, certes subjective, mais qui vous permettra de tirer le plus de ROI de votre management de portefeuille projet !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Portfolio projects kanban status" }, { "type": "feature-split", "reversed": true, "title": "Ritualiser votre portfolio project management", "body": "Un rituel est un ensemble des règles et habitudes fixées - et c’est là l'une clé de votre transformation culturelle réussie. Votre objectif ? Développer de nouvelles habitudes de décisions, communication et coopération, de la journée à l'année, dans vos équipes.<br/><br/>Organisez dans le temps, à intervalles réguliers, vos <a href=\"https://www.airsaas.io/fr/solution/revue-de-portefeuille\">revues de portefeuille stratégique</a>, votre budgétisation participative, ou encore vos réunions de synchronisation du portefeuille. Et tenez-vous-y : la régularité est l’une des clés du succès de l’alignement autour de ces rituels de gouvernance. ---", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "indicateurs limpides" }, { "type": "feature-split", "reversed": false, "title": "Renforcer la culture projet dans votre entreprise", "body": "Votre <a href=\"https://www.airsaas.io/fr/solution/outil-ppm\">outil PPM</a> vous permet d’expliquer à chacun, à même la plateforme, quels sont leurs rôles, comment mieux cadrer des projets en amont, ou encore comment bien communiquer sur les besoins de chaque projet. Cependant, en tant que PMO ou DSI, votre rôle suppose également de promouvoir une véritable culture portfolio project management pragmatique au quotidien.<br/><br/>Pour cela, définissez trois à sept principes d’action à votre management de portefeuille projet. Par exemple, vous pouvez y promouvoir la sincérité, l'auto-organisation, l'empathie et la confiance, la transparence, ou encore la coopération gagnant-gagnant. Ainsi, chacun est aligné autour de ces grands principes, et reste motivé à tout moment.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a6a9328dd6d654d8262628_PMO-DSI.svg", "imageAlt": "les métiers" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Optez pour un outil PPM moderne et simple, où le collaboratif mène vos portefeuilles de projets plus loin, plus rapidement.", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "outil-ppm", "type": "solution", "meta": { "title": "Outil PPM nouvelle génération pour accélérer votre transfo", "description": "Un outil PPM moderne, à l'expérience utilisateur simplissime qui permet d'avoir une visibilité maximale sur votre portefeuille projet", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "AirSaas : un outil PPM nouvelle génération - Logiciel ppm", "subtitle": "Souvent complexes et coûteux à implémenter, AirSaas propose un outil PPM nouvelle génération. Finissez-en aujourd'hui avec votre Excel à 1200 colonnes !", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "intro", "title": "Enfin l’outil PPM que toutes les Directions attendaient" }, { "type": "intro", "subSections": [{ "title": "Prenez des décisions avisées en Copil", "body": "<p>Pour prendre les bonnes décisions il faut les bonnes informations en entrée, à jour et consolidées. La performance de votre activité dépend de votre capacité à être efficace dans la gestion de vos comités de pilotage.<br/>‍<br/>AirSaas vous fourni un tableau de bord de tous vos projets, filtrable suivant les indicateurs essentiels, permettant de ne voir que les informations importantes à la prise de décision.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Gagnez du temps en reporting", "body": "<p>Vos équipes reçoivent régulièrement des questions sur l’état d’avancement des projets, le manager passe beaucoup de temps à remplir des slides Powerpoint en glanant les informations à gauche et à droite.<br/><br/>Nous avons créé pour vous le <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">rapport flash</a>. En un clic une présentation (.ppt, .pdf, url) est générée, contenant les slides projet avec toutes les données à jour. Vous pouvez maintenant tenir au courant la direction générale et les responsables métiers de l’avancée de vos activités, des ressources humaines mobilisées, etc.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Améliorez votre gestion des ressources", "body": "<p>La vue timeline vous permet d’avoir une <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning\">vision d’ensemble des projets</a> en cours et leurs jalons associés. Vous pouvez déplacer les éléments grâce au cliquer-glisser et envisager des nouveaux scénarios. Assurez-vous de la disponibilité des ressources et priorisez les projets par importance, solution ou logiciel choisi, évaluation de l’importance pour le métier, etc.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Suivez la consommation des budgets et des ressources", "body": "<p>Vous ne pouvez pas être pris au dépourvu, vous devez surveiller la consommation de vos budgets et de vos ressources en continu. Pour cela, AirSaas se connecte à vos outils de développement pour récupérer les jours homme consommés et vos outils financiers pour les budgets consommés. L’objectif est de vous fournir une vue consolidée et exportable.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Fluidifiez les relations entre l’IT et les métiers", "body": "<p>Les métiers reprochent la lenteur du département IT et la non prise en compte de leurs besoins. L’IT manque de ressources et reproche aux métiers leur manque d’investissement. AirSaas apporte un workflow commun et une vue consolidée permettant de mettre en avant les jeux de contrainte de chacun.<br/>AirSaas est collaboratif “by design” permettant de rassembler les parties prenantes autour d’un même outil, compréhensible de tous.<br/><br/>L’outil permet un reporting régulier, ainsi qu’une remontée des problèmes rencontrés et des succès du parcours pour engager les équipes et avancer sereinement.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Améliorez la phase de cadrage", "body": "<p>Au menu, un cadrage guidé où les utilisateurs sont accompagnés pour remplir les informations essentielles au bon démarrage (gains espérés, critères de réussite, effort à fournir, etc.), auquel on ajoute la possibilité de les remplir de façon collaborative et asynchrone. Quand le niveau de remplissage est suffisant, le projet peut partir en validation au comité de pilotage.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Augmentez l’engagement des équipes", "body": "<p>Envoyez un sondage régulier et anonyme aux membres de l’équipe pour sonder leur degré de confiance dans le succès du projet. Grâce à l’outil AirSaas, vous créez un lien de coopération entre l’IT et les métiers. Les métiers ne sont plus les clients de l’IT, et l’IT n’est plus au service des métiers. La mise en œuvre d’une collaboration saine est essentielle à la réussite des projets, tout au long de leur cycle de vie.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Partagez vos avancées", "body": "<p>Le plan de communication est indispensable à la réussite de vos projets et de votre équipe. Tenez au courant les membres du Comex et les responsables métier pour diminuer la frustration, mettre en avant les succès et inciter d’autres collaborateurs à rejoindre le mouvement des projets qui fonctionnent. Une tâche qui normalement est chronophage, mais le rapport flash automatique va grandement vous aider !</p>" }] }, { "type": "intro", "subSections": [{ "title": "Le PM : outil de gestion de projet", "body": "<p>Le PM permet d’assurer la gestion d’un projet en particulier. Il va simplifier l’ensemble des missions du chef de projet :</p><ul><li>contrôle du respect des objectifs</li><li>gestion des délais de réalisation</li><li>optimisation de suivi des actions de chaque membre de l’équipe</li><li>planification de l’exécution de chaque phase de la gestion du projet</li><li>offrir une visibilité sur la gestion de l’ensemble du projet grâce à un tableau de bord</li><li>animer les équipes en charge de la gestion du projet</li></ul>" }] }, { "type": "intro", "subSections": [{ "title": "Le PPM : outil de gestion de portefeuille de projets", "body": "<p>Là où le PM optimise la planification d’un projet en particulier, un outil PPM va permettre d’organiser tous les projets d’une organisation.<br/>Lorsqu’une entreprise évolue continuellement, elle arrive forcément à un stade où elle sera amenée à assurer la gestion de plusieurs projets en même temps. Et c’est justement lorsque ce nombre de projets commence à devenir important que les logiciels de gestion de portefeuille de projets deviennent indispensables.</p><ul><li>prioriser les projets</li><li>offrir une visibilité globale sur la gestion de projets</li><li>garantir une transparence sur la gestion du portefeuille de projet</li><li>responsabiliser les chefs de projets et leur assignant des objectifs</li><li>sortir des logiques de silos et installer une approche collaborative</li></ul>" }] }, { "type": "intro", "title": "Un bref retour historique sur les outils PPM" }, { "type": "intro", "subSections": [{ "title": "Quand est-ce que les logiciels ppm ont commencé à apparaître ?", "body": "<p>Si les premiers outils de gestion de projet ont commencé à apparaître dès les années 80, on remarque tout de même que de nouvelles entreprises ont depuis continué de développer des logiciels concurrents. Une autre chose intéressante : si ces logiciels répondent aujourd’hui tous aux problématiques de gestion de portefeuilles de projets, chacun d’entre eux n’a pas initialement été développé pour servir les mêmes objectifs ! Certains priorisaient la gestion de projets, tandis que d’autres abordaient dès le début la gestion des portefeuilles de projets.</p>" }] }, { "type": "intro", "body": "<p>Problématique ciblée à la date de création</p>", "subSections": [{ "title": "Quel besoin est apparu en premier : la gestion de projet ou de portefeuille de projets ?", "body": "<p>On peut voir qu’une majorité des outils de gestion de portefeuille projets ont en fait commencé par proposer des services de gestion de projet ! Ce n’est que par la suite, que ces derniers ont été complétés afin de permettre de mener plusieurs projets de front de manière optimale.</p><p>‍</p>" }] }, { "type": "intro", "body": "<p>On peut quand même noter que des outils étaient axés dès le début sur la gestion de portefeuille projets (Planview), même si certains d’entre eux proposaient en parallèle des fonctions de gestion de projet (Sciforma, Ganttic).<br/><br/>Aujourd’hui, la quasi-totalité de ces logiciels répondent aux deux besoins : la gestion de projet et la gestion de portefeuille de projets. On constate donc bien qu’il existe une nécessité de fluidifier la prise de décision dans les entreprises, que ce soit à l’échelle de la gestion d’un projet, ou à une échelle plus globale à l’aide d’un outil PPM.</p>" }, { "type": "intro", "subSections": [{ "title": "La gestion de projet : d’un prisme technique à un prisme business", "body": "<p>La plupart des livres blancs sur le sujet s’accordent à dire que dans les dernières décennies, la DSI est passée d’un rôle largement cantonné à un aspect technique à une mission centrée sur les besoins business des métiers. La DSI n’est plus réduite à assurer le fonctionnement du run, en fournissant une assistance purement technique, mais elle doit aussi comprendre les besoins des différents collaborateurs afin de leur apporter de la valeur dans leur coeur de métier.<br/><br/>Les attentes qu’ont les DSI d’un outil pour piloter leurs projets ont donc forcément énormément évoluées : d’un outil de suivi de gestion des problématiques techniques, les DSI ont souvent besoin que leur PPM simplifie la communication avec les métiers et la remontée de leurs besoins, notamment en passant par l’intermédiaire du chef de projet.</p>" }] }, { "type": "intro", "subSections": [{ "title": "L’impact de l’essor du poids du digital sur les besoins des DSI en gestion de projets", "body": "<p>Le développement du digital permet aux DSI d’aider leur entreprise de manière différente, et notamment en contribuant davantage à la réussite des objectifs business. Par exemple, une DSI peut structurer la digitalisation des process, ce qui entraîne des gains de temps pour les métiers et aide ces derniers à être compétitifs face aux entreprises concurrentes. Elle peut même participer à la création de valeur, notamment en accompagnant le changement de business modèle de l’entreprise. On peut aussi penser à l’anecdote de Pierre Raschi, DG de Référence DSI, où il raconte comment une DSI en temps partagé a permis à une boucherie de renouveler sa clientèle vieillissante grâce au digital.</p><p>Ce changement structurel du poids du digital pour une entreprise amène donc à confier davantage de missions à la DSI. Ainsi, puisque la DSI a de nouvelles responsabilités, elle pilote ses projets différemment, et attend donc de nouvelles fonctionnalités de la part de ses outils PPM, ce qui amène ces derniers à évoluer !</p>" }] }, { "type": "intro", "subSections": [{ "title": "Un changement de paradigme : du contrôle des process, à un besoin d’impliquer les collaborateurs", "body": "<p>Les deux changements que l’on a vus ci-dessus impliquent une évolution dans la manière qu’a la DSI de collaborer avec les différents services et équipes de son entreprise. Une DSI axée sur la technique essayait plutôt de contrôler les comportements des collaborateurs afin qu’ils ne soient freinés par aucun problème technique et que le SI ne soit pas affecté négativement. Aujourd’hui, si elle veut réussir à impacter le business de l’entreprise de manière positive, la DSI doit être capable de comprendre finement les besoins des métiers et donc de collaborer étroitement avec ces derniers. Et une telle collaboration nécessite de briser les silos qui peuvent exister entre les services, ou au sein même des équipes, et d’impliquer chacun des collaborateurs. Ainsi, une DSI qui souhaite contrôler tous les processus existants n’aura pas besoin du même type d’outil que celle qui cherche à structurer une collaboration forte avec ses collaborateurs.</p>" }] }, { "type": "intro", "body": "<p><br/>En grossissant le trait, on peut matérialiser deux visions majeures de DSI qui s’opposent grâce à ces pyramides de Maslow :</p>" }, { "type": "intro", "subSections": [{ "title": "Des PPM variés selon les besoins de sa DSI", "body": "<p>Bien sûr, il existe des PPM qui proposent différentes fonctionnalités, plus ou moins poussées :</p><ul><li>arbitrage des projets</li><li>pilotage des ressources</li><li>construction budgétaire</li><li>gestion des risques</li></ul><ul><li>animation des instances projet</li><li>reporting des informations essentielles</li><li>contrôle de la rentabilité</li><li>espace de communication simplifié</li></ul><p>Mais au-delà de cette liste de fonctionnalités, il est possible de mettre en avant des styles de PPM opposés pour les différencier plus facilement.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Les PPM tout-en-un VS les PPM qui s’intègrent aux applications existantes", "body": "<p>Certains PPM comme les ERP ambitionnent de répondre à tous les besoins des DSI sur un seul et même logiciel. Bon nombre d’entre eux sont efficaces, mais le manque de flexibilité d’une telle solution une fois implémentée oblige à prendre le temps de s’interroger avant de faire son choix.</p><p>A l’inverse, d’autres logiciels (souvent des SaaS) offrent moins de fonctionnalités mais proposent de s’intégrer aux outils existants. Ils permettront ainsi d’éviter les doublons et de diminuer le coût de change d’un outil : là où la montée de version d’un outil PPM lourd sera un projet majeur, long, et coûteux.<br/><br/>Ces deux types d’outils ne correspondent pas à la même vision du rôle de la DSI. Dans le cas des logiciels qui s’intègrent à l’existant, la DSI est perçue comme n’ayant plus à acquérir un outil lui permettant d’avancer sur tous les fronts, mais plutôt comme devant être capable de connecter et de déconnecter différents outils, en fonction de l’évolution de l’entreprise. L’idée est d’être en capacité de coller aux besoins existant, constamment, et à moindre coût.</p><p>‍</p>" }] }, { "type": "intro", "subSections": [{ "title": "Les PPM qui proposent un espace d’échange collaboratif", "body": "<p>Selon la vision qu’aura le DSI de son rôle pour l’entreprise, un espace collaboratif incorporé directement dans son outil PPM peut vraiment simplifier son quotidien et celui de ses équipes. Si la plupart des entreprises utilisent déjà des canaux “classiques” pour faire remonter les besoins métiers à la DSI (Teams, Slack), faire le choix d’utiliser un PPM qui propose une interface d’échange plus structurée permet de centraliser l’information afin de collaborer plus efficacement.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Les PPM qui misent sur l’UX", "body": "<p>L’avantage qu’amène le choix de ces PPM est double. Tout d’abord, si l’on souhaite impliquer les collaborateurs d’une entreprise sur des sujets aussi techniques que ceux traités par la DSI, mieux vaut le faire sur une interface qui leur plaira. Il n’y a rien de plus décourageant que d’être invité à travailler sur un Excel géant lorsque l’on n'est pas la personne ayant passé des dizaines d’heures à le créer. Les PPM qui misent sur l’UX ont donc généralement une interface suffisamment intuitive pour faciliter la collaboration entre les profils techniques et business.</p><p>Le second avantage est d’augmenter le taux d’adoption de ces PPM : les collaborateurs ne mettront que quelques heures à se roder à l’utilisation de ces nouveaux logiciels plutôt que quelques jours, ce qui peut être un levier très intéressant si l’objectif est de mobiliser rapidement.</p><p>‍</p>" }] }, { "type": "intro", "subSections": [{ "title": "L’importance d’adapter la méthodologie portée par l’outil à la réalité de son organisation", "body": "<p>Aucun outil n’est réellement neutre, chacun d’entre eux porte intrinsèquement une méthodologie. Si l’on souhaite maximiser le taux d’adoption de son outil PPM, l’un des facteurs clé est d’en choisir un qui porte une méthodologie adaptée au fonctionnement de son organisation : aux niveaux des processus existants , des objectifs fixés, ou même de sa vision de la gestion de projets.<br/><br/>Prendre un outil PPM portant une méthodologie opposée à celle qui est en place serait aussi contre-productif que de nager à contre-courant. Ainsi, il est primordial de s’interroger sur la méthodologie que l’on souhaite appliquer, afin de choisir son outil PPM en conséquence.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Changer la culture d’une entreprise grâce à l’interface utilisateur", "body": "<p>S’il vaut mieux adopter un outil dont la méthodologie est proche de la réalité de votre fonctionnement, un outil PPM peut aussi être un levier pour faire évoluer vos méthodes de travail ainsi que la culture de votre entreprise. En effet, la culture d'une entreprise est le fruit du comportement qu'elle adopte face à un environnement particulier. Donc si l'on change l'environnement, notamment en changeant les logiciels utilisés, on change la culture !<br/><br/>Il est donc possible de se servir d’un nouvel outil pour impulser un changement de pratiques. Cependant, il faut tout de même veiller à ce que le changement souhaité ne soit pas à l’opposé de ce que vous promouvez actuellement. En effet, s’il n’est pas accompagné par des décisions et des directives allant dans le même sens, un outil à lui seul ne peut pas bousculer les habitudes ancrées dans une organisation.<br/></p>" }] }, { "type": "intro", "body": "<p>Pour résumer : choisissez un outil qui porte une méthodologie proche de celle que vous promouvez actuellement ou au moins de celle que vous souhaitez instaurer.<br/></p>" }, { "type": "intro", "title": "Où se situe AirSaas dans le spectre de tous ces outils de gestion de projet ?", "body": "<p>Comme décrit en haut de page, AirSaas est un outil de gestion de portefeuilles projets plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités clé dont une DSI a besoin pour assurer l’exécution de ses projets.<br/></p>" }, { "type": "intro", "subSections": [{ "title": "Un outil PPM intuitif et intégré à vos outils existant", "body": "<p><strong>Jira<br/></strong><br/>En s’intégrant à Jira vous aurez automatiquement les données d’avancement des projets dans AirSaas. Cela vous permettra d’avoir une vue globale de l’ensemble des projets et de leurs états d’avancement sans efforts.</p>" }] }, { "type": "intro", "body": "<p><strong>Microsoft Teams<br/>‍</strong><br/>AirSaas est intégré à Microsoft Teams. Automatiquement les informations les plus importantes sur les projets en cours seront envoyées sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pourrez partager simplement l’avancée des projets avec l’ensemble de l’entreprise. Si vous utilisez d’autres solutions, n’hésitez pas à nous le dire !</p>" }, { "type": "intro", "subSections": [{ "title": "Un outil PPM avec une UX forte", "body": "<p>Notre pari : pour parvenir à impliquer les métiers, la DSI a besoin de le outil PPM qu’ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n’est pas en forçant les métiers à travailler sur des outils complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.</p>" }] }, { "type": "intro", "body": "<p><strong>AirSaas</strong>est donc solution PPM légère, qui s’intègre à l’existant, et qui porte une méthodologie collaborative forte afin d’impliquer les métiers.<br/></p>" }, { "type": "feature-split", "reversed": false, "title": "Prenez des décisions avisées en Copil", "body": "Pour prendre les bonnes décisions il faut les bonnes informations en entrée, à jour et consolidées. La performance de votre activité dépend de votre capacité à être efficace dans la gestion de vos comités de pilotage.<br/>‍<br/>AirSaas vous fourni un tableau de bord de tous vos projets, filtrable suivant les indicateurs essentiels, permettant de ne voir que les informations importantes à la prise de décision.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions" }, { "type": "feature-split", "reversed": true, "title": "Gagnez du temps en reporting", "body": "Vos équipes reçoivent régulièrement des questions sur l’état d’avancement des projets, le manager passe beaucoup de temps à remplir des slides Powerpoint en glanant les informations à gauche et à droite.<br/><br/>Nous avons créé pour vous le <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">rapport flash</a>. En un clic une présentation (.ppt, .pdf, url) est générée, contenant les slides projet avec toutes les données à jour. Vous pouvez maintenant tenir au courant la direction générale et les responsables métiers de l’avancée de vos activités, des ressources humaines mobilisées, etc.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting flash avec votre logiciel PPM" }, { "type": "feature-split", "reversed": false, "title": "Améliorez votre gestion des ressources", "body": "La vue timeline vous permet d’avoir une <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning\">vision d’ensemble des projets</a> en cours et leurs jalons associés. Vous pouvez déplacer les éléments grâce au cliquer-glisser et envisager des nouveaux scénarios. Assurez-vous de la disponibilité des ressources et priorisez les projets par importance, solution ou logiciel choisi, évaluation de l’importance pour le métier, etc.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Gestion des ressources depuis votre outil PPM" }, { "type": "feature-split", "reversed": true, "title": "Suivez la consommation des budgets et des ressources", "body": "Vous ne pouvez pas être pris au dépourvu, vous devez surveiller la consommation de vos budgets et de vos ressources en continu. Pour cela, AirSaas se connecte à vos outils de développement pour récupérer les jours homme consommés et vos outils financiers pour les budgets consommés. L’objectif est de vous fournir une vue consolidée et exportable.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d705feadffd7e3d62baec2_Project%20page%20effort%20and%20budget%20consumed.webp", "imageAlt": "Project page effort and budget consumed" }, { "type": "feature-split", "reversed": false, "title": "Fluidifiez les relations entre l’IT et les métiers", "body": "Les métiers reprochent la lenteur du département IT et la non prise en compte de leurs besoins. L’IT manque de ressources et reproche aux métiers leur manque d’investissement. AirSaas apporte un workflow commun et une vue consolidée permettant de mettre en avant les jeux de contrainte de chacun.<br/>AirSaas est collaboratif “by design” permettant de rassembler les parties prenantes autour d’un même outil, compréhensible de tous.<br/><br/>L’outil permet un reporting régulier, ainsi qu’une remontée des problèmes rencontrés et des succès du parcours pour engager les équipes et avancer sereinement.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Améliorez la phase de cadrage", "body": "Au menu, un cadrage guidé où les utilisateurs sont accompagnés pour remplir les informations essentielles au bon démarrage (gains espérés, critères de réussite, effort à fournir, etc.), auquel on ajoute la possibilité de les remplir de façon collaborative et asynchrone. Quand le niveau de remplissage est suffisant, le projet peut partir en validation au comité de pilotage.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d473f144eace1121240b18_Modal%20-%20create%20project.webp", "imageAlt": "Cadrage de projet dans votre logiciel PPM" }, { "type": "feature-split", "reversed": true, "title": "Partagez vos avancées", "body": "Le plan de communication est indispensable à la réussite de vos projets et de votre équipe. Tenez au courant les membres du Comex et les responsables métier pour diminuer la frustration, mettre en avant les succès et inciter d’autres collaborateurs à rejoindre le mouvement des projets qui fonctionnent. Une tâche qui normalement est chronophage, mais le rapport flash automatique va grandement vous aider !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d706b1f7b6d596a3ed07bc_Project%20page%20feed.webp", "imageAlt": "Project page\n" }, { "type": "feature-split", "reversed": false, "title": "Le PM : outil de gestion de projet", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65df5fc43b89570d447c3af6_Graphic-PM.webp", "imageAlt": "Le PM : outil de gestion de projet" }, { "type": "feature-split", "reversed": true, "title": "Le PPM : outil de gestion de portefeuille de projets", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Portfolio projects list" }, { "type": "feature-split", "reversed": true, "title": "Les PPM qui misent sur l’UX", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65df6a73003911b97babb1a4_Graphic-activities.webp", "imageAlt": "Activities" }, { "type": "feature-split", "reversed": true, "title": "Un outil PPM avec une UX forte", "body": "Notre pari : pour parvenir à impliquer les métiers, la DSI a besoin de le outil PPM qu’ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n’est pas en forçant les métiers à travailler sur des outils complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70979f3aaee0cbfd859cc_Feed%20search%20solution.webp", "imageAlt": "Un outil PPM avec une UX forte" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "outils-de-pilotage-projet", "type": "solution", "meta": { "title": "Outil de pilotage de projet pour simplifier votre gouvernance", "description": "La gestion ne se résume pas à un Gantt : choisissez l'outil de pilotage de projet le plus simple au monde, et menez votre transformation d'entreprise plus loin", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Une nouvelle manière de voir les outils de pilotage projet", "subtitle": "Parce que la gestion ne se résume pas à un Gantt, AirSaas propose un outil de pilotage de projet qui simplifie votre reporting, votre gouvernance et votre communication projet", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "intro", "title": "Valorisez le travail de votre équipe" }, { "type": "intro", "title": "Les différentes typologies d’outils de pilotage de projet", "body": "<p>Il existe différents types de pilotage de projet, qui ne servent pas les mêmes objectifs. Pourtant, il n’est pas rare qu’il y ait des confusions, notamment entre ceux qui permettent le pilotage d’un projet, et ceux qui visent à simplifier la gestion d’un portefeuille de projets.<br/></p>" }, { "type": "intro", "body": "<ul><li>Respecter lesobjectifs de chaque équipe</li><li>S’assurer de la tenue des délais d’exécution de chacun</li><li>Assurer un suivi global de l’avancée de toutes les équipes</li><li>Organiser la planification de toutes les étapes nécessaires au projet via un tableau de bord</li><li>Engager les collaborateurs travaillant sur le projet grâce à un espace collaboratif</li></ul>" }, { "type": "intro", "body": "<p>‍</p><p>Les petites entreprises qui n’ont que peu de projets n’ont pas forcément besoin d’outils permettant le pilotage de portefeuilles de projets. Mais à mesure qu’elles grandissent, les projets se multiplient, jusqu’à ce qu’une gestion globale et organisée de l’ensemble des projets prenne énormément de temps à chaque chef de projet ou au comité de pilotage : c’est le signe qu’il faut sûrement investir dans un tel outil.</p><p>‍</p><p>Un outil de pilotage de portefeuilles de projets permet de :</p><ul><li>Hiérarchiser l’importance de chaque projet</li><li>Donner une visibilité totale sur la conduite de l’ensemble des projets</li><li>Permettre au chef de projet ou au comité de pilotage de connaître l’avancée de chaque projet</li><li>Préciser les missions que doivent accomplir chaque responsable de projet</li><li>Instaurer une méthodologie collaborative entre les équipes et les services de l’entreprise</li></ul>" }, { "type": "intro", "title": "La naissance récente des outils de pilotage de projet" }, { "type": "intro", "body": "<p>Il faut tout de même relever que certains logiciels comme Planview avaient pris la décision de centrer leur solution sur la gestion des portefeuilles projets dès leur création, et que d’autres outils comme Sciforma ou Ganttic répondaient d’emblée aux deux problématiques : la gestion de projet unique, et de portefeuille de projets !</p><p>L’écrasante majorité des outils de pilotage de projet traite aujourd’hui ces deux problématiques dès leur création : il y a un besoin de simplifier la prise de décision entre les différents acteurs, que ce soit à l‘échelle d’un projet unique, ou au niveau plus global du portefeuille de projets.</p><p>S’ils ont des similitudes dans les objectifs qu’ils visent, les outils de pilotage de projet peuvent avoir des fonctionnalités assez différentes. L’origine de ces différences est double : selon le besoin auquel l’outil a été conçu pour répondre en premier, mais aussi en fonction de la vision du pilotage de projet qu’ils promeuvent.</p>" }, { "type": "intro", "title": "Des visions hétérogènes de la gestion de projet selon les DSI et le style de chef de projet", "body": "<p>Plusieurs raisons font que les logiciels de pilotage de projets peuvent proposer des fonctionnalités variées : la manière dont ils ont été développé à l’origine a une influence, mais leurs fonctionnalités dépendent aussi de la vision de la gestion de projets qu’ils promeuvent. Mais pourquoi plusieurs visions de la gestion de projet coexistent-elles dans les DSI ?<br/></p>" }, { "type": "intro", "subSections": [{ "title": "L’évolution du rôle de la DSI : d’une fonction centrée sur le contrôle à une nécessité de collaborer avec les métiers", "body": "<p>Les deux évolutions que l’on a décrites plus haut ont pour conséquence de transformer la manière dont la DSI doit collaborer avec les métiers de son entreprise. Si on prend l’exemple d’une DSI axée sur la technique, une de ses priorités va être de s’assurer du bon fonctionnement du run afin qu’aucun collaborateur n’ait à souffrir de problèmes purement techniques. Mais si la DSI a pour ambition d’apporter de la valeur à son entreprise d’un point de vue business, elle doit se donner les moyens d’échanger régulièrement avec les métiers afin de comprendre de quelle manière elle pourrait les aider à atteindre leurs objectifs business. Or, structurer une telle collaboration n’est pas chose aisée, a fortiori lorsque les différents services ne sont pas habitués à travailler ensemble.</p><p>Une DSI qui vise à contrôler les comportements de ses collaborateurs pour éviter d’affecter négativement le SI n’aura pas du tout besoin du même type d’outil de pilotage projet que celle qui ambitionne d’instaurer un dialogue fort avec les métiers en vue de leur apporter de la valeur dans leur coeur de métier.</p>" }] }, { "type": "intro", "body": "<p><br/>Pour matérialiser un idéal type de ces deux visions opposées du rôle d’une DSI, il est possible de le faire à partir de ces pyramides de Maslow :</p>" }, { "type": "intro", "title": "Choisir son outil en fonction de sa vision du pilotage de projet", "body": "<p>On a vu que les outils de pilotage de projet n’offrent pas tous les mêmes fonctionnalités. La meilleure manière de trouver l’outil idéal à acquérir est donc de s’interroger sur sa vision du pilotage de projet : quels sont mes attentes et objectifs, et plus que ça, quelle est la place qui est attendue de la DSI dans mon entreprise ?<br/></p>" }, { "type": "intro", "subSections": [{ "title": "Des outils de gestion de portefeuille projets diversifiés", "body": "<p>Tout d’abord, il faut noter que les outils de pilotage de portefeuille projet peuvent présenter de nombreuses fonctionnalités différentes qui permettent notamment de :</p><ul><li>Gérer et attribuer les ressources disponibles</li><li>Prioriser et hiérarchiser les projets</li><li>Engager et responsabiliser le chef de projet</li><li>Gérer les budgets engagés</li></ul><ul><li>Gérer les risques</li><li>Centraliser les informations clés</li><li>Évaluer la rentabilité de chaque projet</li><li>Communiquer dans un espace collaboratif structuré</li></ul><p>Mais plus que de dresser une liste des fonctionnalités que peuvent comporter ces logiciels, il est intéressant de remarquer que des différences de styles entre outils plus structurantes existent.</p>" }] }, { "type": "intro", "body": "<p>Chacun de ces deux types d’outils présente des avantages et des inconvénients. Un ERP complet permet de centraliser toutes les actions sur un même logiciel, mais présente l’inconvénient d’être complexe à faire évoluer : en effet, ces solutions sont peu flexibles et leur montée de version est lente et coûteuse.</p><p>A l’inverse, un outil de gestion de projet spécialisé présente l’inconvénient de ne pas proposer autant les fonctionnalités, mais offre d’autres avantages : il est plus rapide à implémenter, et permet de réduire le coût de change lorsque l’entreprise évolue.</p><p>Encore une fois, il n’existe pas de solution idéale : tout dépend de votre vision du rôle de la DSI et des attentes que vous avez de vos outils de gestion de portefeuille de projets. Certaines DSI préfèrent acquérir un logiciel lourd qui répond à l’ensemble de leurs besoins actuels, là ou d’autres font le choix d’être en capacité d’installer et de désinstaller des solutions rapidement et à coût réduit, en fonction de l’évolution des besoins de leur entreprise.</p>" }, { "type": "intro", "body": "<p>Ainsi les outils ayant misé sur l’UX simplifient la collaboration entre des profils business et des profils techniques en proposant une interface compréhensible rapidement par toutes les parties prenantes, tout en maximisant le taux d’adoption général du logiciel.</p>" }, { "type": "intro", "subSections": [{ "title": "Prendre compte les méthodologies intrinsèques de chaque outil", "body": "<p>Tout outil porte nécessairement une méthodologie plus ou moins poussée en lui. L'adéquation entre la méthodologie portée par un outil et celle déjà en place dans l’entreprise qui l’utilise est un facteur clé du taux d’adoption de ce logiciel par les collaborateurs.</p><p>En effet, il faut que la méthodologie intrinsèque de votre outil corresponde à vos processus de travail, à vos objectifs et à votre vision du pilotage de projet. Autrement, chacun de vos collaborateurs devra redoubler d'efforts pour prendre le logiciel en main et s’en servir, ce qui réduira forcément son taux d’adoption et donc, son impact dans l’entreprise.</p><p>Il faut donc s’interroger sur les pratiques mises en place dans votre DSI avant de choisir l’outil de pilotage de projet le plus adapté aux process existants et ainsi, maximiser son influence sur vos collaborateurs.</p>" }] }, { "type": "intro", "subSections": [{ "title": "L’outil de gestion de projet comme vecteur de changement de culture d’une entreprise", "body": "<p>S’il est préférable d’adapter son choix d’outil à la méthodologie déjà mise en place dans l’entreprise, il faut tout de même remarquer que l’on peut aussi se servir d’un outil de gestion de pilotage projet comme d’un levier pour impulser des changements dans les habitudes de travail existantes. En effet, la culture de l’entreprise est le fruit de son environnement - un environnement dont font partie les logiciels que vous utilisez ! En changeant les outils de vos collaborateurs, vous allez donc pouvoir influer sur la culture de l’entreprise, mais aussi sur ses méthodes de travail.</p><p>Cependant, si les outils de gestion de projet sont des leviers pertinents pour amener vos collaborateurs vers un changement de pratiques, il ne faut pas surestimer leur impact. En effet, se contenter d’investir dans un nouvel outil ne suffit pas à révolutionner les pratiques en place depuis plusieurs années.</p><p>Deux conditions sont primordiales pour maximiser l’impact de l’outil. D’abord, il faut accompagner la mise en place de l’outil par des directives et des consignes allant dans le même sens que le changement que l’on veut créer. Mais il faut aussi que la méthodologie portée par l’outil ne soit pas trop éloignée de celle qui existe actuellement dans votre entreprise , car transformer complètement les pratiques est compliqué et ne peut se faire que sur le temps long.<br/></p>" }] }, { "type": "intro", "body": "<p>En conclusion: l’idéal est donc d’orienter votre choix vers un outil portant une méthodologie proche de celle qui est déjà en place dans votre entreprise, ou au moins de celle que vous aimeriez installer.<br/></p>" }, { "type": "intro", "title": "Quel type d’outil de pilotage de projet est AirSaas ?", "body": "<p>AirSaas est un PPM plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités-clés dont une DSI a besoin pour assurer l’exécution de ses projets.<br/></p>" }, { "type": "intro", "subSections": [{ "title": "Un outil de pilotage projet souple et intégrable facilement", "body": "<p><strong>Jira<br/></strong><br/>En intégrant Jira.à AirSaas, vous obtenez automatiquement les données d’avancement des projets dans la plateforme. Cela vous permet d’avoir une vue globale de l’ensemble des projets et de leurs états d’avancement sans efforts.</p>" }] }, { "type": "intro", "body": "<p><strong>Microsoft Teams<br/>‍</strong><br/>AirSaas est intégré à Microsoft Teams. Automatiquement, les informations les plus importantes sur les projets en cours sont envoyées sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pouvez partager simplement l’avancée des projets avec l’ensemble de l’entreprise. Si vous utilisez d’autres solutions, n’hésitez pas à nous le dire !</p>" }, { "type": "intro", "body": "<p>Nous avons poussé la logique collaborative jusqu’au bout : AirSaas propose un moteur de recherche de solutions (externes/internes) accessibles aux responsables métiers. Lorsqu’un métier a un besoin, il cherche déjà des solutions de son côté sans forcément prévenir la DSI qui peut même se retrouver face à du Shadow IT.</p><p>Notre idée ici est de donner les outils à la DSI pour encadrer ces pratiques et structurer leurs efforts de recherche de solution en leur faisant comprendre les contraintes techniques du SI.</p>" }, { "type": "intro", "body": "<p><strong>AirSaas</strong> est un PPM léger, qui s’intègre à l’existant, et qui porte une méthodologie collaborative forte afin d’impliquer les métiers.<br/></p>" }, { "type": "feature-split", "reversed": false, "title": "Accompagnez le cadrage des projets", "body": "Un bon projet est un projet bien préparé. Pourtant, 90% des fiches de cadrage sont incomplètes. Sur AirSaas, nous guidons vos collaborateurs dans le remplissage des informations essentielles à un bon cadrage.<br/>Les fiches de cadrage sont dynamiques et collaboratives. Vos équipes peuvent itérer ensemble jusqu'à que le projet soit validé.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d473f144eace1121240b18_Modal%20-%20create%20project.webp", "imageAlt": "cadrage de projet" }, { "type": "feature-split", "reversed": true, "title": "Le pilotage de projet par la valeur", "body": "Tous les projets ne se valent pas. En tant que partenaire business, vous devez proposer une méthode pour <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">piloter les projets IT</a> suivant des indicateurs-clés.<br/>AirSaas propose une vue filtrable avec toutes les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">informations consolidées</a> pour prendre des décisions avisées.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Reportez en un clic", "body": "Vous êtes au centre des attentions et devez tenir au courant les responsables métiers et votre direction de l'avancée des projets. Pour cela, nous avons créé les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">rapports flash automatisés</a>.<br/>En un clic, générez un <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-gestion-de-projet\">rapport</a>(.ppt, .pdf, url) avec les détails d'avancée des projets, les points d'attention et tous les indicateurs à jour.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash" }, { "type": "feature-split", "reversed": true, "title": "Prenez de la hauteur", "body": "Rien ne vous échappe grâce à la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/macro-planning\">vue timeline</a>. Prenez de la hauteur et profitez d’un panorama sur tous les projets en cours et leurs jalons associés. <br/>Déplacez les éléments grâce au cliquer-glisser et testez des nouveaux arrangements en fonction des disponibilités des parties prenantes et de l’urgence des projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Vue timeline macro" }, { "type": "feature-split", "reversed": false, "title": "Diminuez la friction avec les métiers", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a7bb239ce496a6f00ac37f_metier-it.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Augmentez le taux de réussite des projets IT", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4c030f0e65_Ameliorez-.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Communiquez mieux en interne", "body": "La mise en place d’un plan de communication est bénéfique dans l’ensemble des entreprises et augmente la performance des DSI. Destiné aux membres du Comex et aux responsables métiers, il a l’avantage de diminuer la frustration, valoriser les équipes IT, et former l’ensemble des responsables aux méthodes qui fonctionnent. Une bonne communication de suivi d’avancée est d’autant plus importante avec un fonctionnement à distance. Le rapport flash automatique est votre meilleur allié !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65cb1c26011557f1b1f33b74_Graphic%20Communiquez%20interne.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Les outils de pilotage d’un projet unique : la gestion de projet", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fdab9a0f0e4a_outil8.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Les outils de pilotage de projets multiples : la gestion de portefeuilles de projets", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "outil PPM" }, { "type": "feature-split", "reversed": false, "title": "Depuis combien de temps les outils de pilotage de projet sont-ils utilisés ?", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd6f640f0e4f_outil10.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Quel a été le premier besoin à apparaître : le pilotage de projet unique ou la gestion de portefeuille de projets ?", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd8da50f0e50_outil11.svg", "imageAlt": "Quel besoin est apparu en premier : la gestion de projet ou de portefeuille de projets ?" }, { "type": "feature-split", "reversed": false, "title": "D’une gestion de projets axée sur la technique au focus business", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd42890f0e53_outil12.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "La gestion de projets dans les DSI transformée par l’avènement du digital", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd08150f0e54_outil13.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Les outils de gestion de projet : all-in-one VS spécialisés", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4a760f0e5b_outil15.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Les outils de gestion de portefeuille projet centrés sur l’expérience utilisateur", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72e40db63dfa85954ccc5_Feed%20main.webp", "imageAlt": "outil PPM" }, { "type": "feature-split", "reversed": true, "title": "Un outil de pilotage projet avec une méthodologie pensée pour impliquer les métiers", "body": "Notre pari : pour parvenir à impliquer les métiers, la DSI doit leur proposer un outil qu’ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n’est pas en forçant les métiers à travailler sur des outils complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "outil PPM" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "portfolio-management", "type": "solution", "meta": { "title": "La solution de portfolio management qui booste votre transformation", "description": "Faites passer votre portfolio management à la vitesse supérieure avec une solution qui fluidifie votre prise de décision et automatise votre reporting", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "La solution de portfolio management qui accélère la transformation de votre entreprise", "subtitle": "La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les problèmes les plus fréquents en gestion de portefeuille de projets. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Une plateforme de gouvernance projet à la hauteur de vos ambitions", "body": "<p>Notre mission ? Vous permettre de devenir le pivot de la transformation de l’entreprise en structurant la gouvernance de tous les projets, grâce à une plateforme simple que le top management va adorer. La vôtre ? Faire passer votre entreprise à l’étape supérieure en gouvernance de projet !</p>" }, { "type": "intro", "title": "Un capacity planning par équipe simple et actionnable", "body": "<p>Visualisez en un clin d'oeil si vous êtes dans les clous... ou dans les choux. Grâce à cette vue vous avez les bases d'une discussion pragmatique pour prendre les décisions :</p><p>‍</p><p>‍</p>" }, { "type": "intro", "title": "5 bonnes pratiques de portfolio management pour transformer votre entreprise plus efficacement", "body": "<p>Avoir un bon logiciel de gestion de portefeuille projet est crucial. Mais n’oubliez pas d’appliquer ces cinq bonnes pratiques à votre portfolio management au quotidien, pour en faire un véritable outil opérationnel et collaboratif, au service de votre transfo.<br/></p>" }, { "type": "intro", "title": "Grâce à sa marketplace AirSaas s’intègre nativement à vos outils du quotidien", "body": "<p>Centralisez toutes vos informations cruciales (tickets, jalons…) depuis vos outils de gestion de tâches sur AirSaas, et diffusez-les via vos canaux de communication interne. Tout le monde est au diapason, et vous gouvernez de manière optimale.</p>" }, { "type": "intro", "title": "Laissez nos clients vous parler d’AirSaas", "body": "<p>Qui de mieux pour vous parler de la plateforme que ceux qui l’utilisent au quotidien pour améliorer la gestion de leurs projets de transformation ?</p>" }, { "type": "feature-split", "reversed": false, "title": "Partagez simplement les roadmaps à toute l'organisation", "body": "Une roadmap, ça bouge, ça vit, c'est un élément clé pour aligner le top management en continu. Avec AirSaas, plus besoin de faire des PowerPoints à rallonge : l'information est centralisée, partageable et sympa à visualiser (parce que quand c'est beau, c'est quand même plus impactant).", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline" }, { "type": "feature-split", "reversed": false, "title": "Chaque directeur définit ses prios", "body": "Demandez aux directeurs de prioriser parmi les projets dont son équipe est à l'origine. Deux projets ne peuvent pas avoir la même priorité. Une fois prêts, ils valident leur choix. C'est simple, transparent et puissant.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07a346b12e77e37ddd72_Prioritization%20per%20team%20ppt%20d%26d.webp", "imageAlt": "Priorisation options" }, { "type": "feature-split", "reversed": true, "title": "Diffusez un cadrage projet standardisé", "body": "Remplissez les fiches cadrage de projet de manière collaborative, et guidez vos collaborateurs vers un véritable niveau d’excellence en gestion de projet. A vous une culture projet homogénéisée !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Presentation scope" }, { "type": "feature-split", "reversed": false, "title": "Votre reporting projet en un clic", "body": "Générez votre <strong>reporting flash en un seul clic</strong>, et homogénéisez vos présentations, pour faciliter la prise de décision. Autant de temps gagné pour vous focaliser sur le coaching de vos chefs de projet et votre gouvernance.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report ppt" }, { "type": "feature-split", "reversed": true, "title": "Fluidifiez votre prise de décisions importantes et urgentes", "body": "<strong>Centralisez vos décisions</strong> sous forme de Kanban, et partagez-les aisément avec toutes les parties prenantes de vos projets. Finies les informations perdues dans vos mails ou flux de discussions instantanées !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions" }, { "type": "feature-split", "reversed": false, "title": "Commencez par un cadrage de projet optimal", "body": "Vous le savez mieux que quiconque : il est crucial de savoir qui fait quoi dans chaque projet. Qui est le sponsor ? Qui sont les key users ? Quel chef de projet prend quoi en charge ? Vous devez mettre en place les droits, devoirs et règles que chacun doit suivre, pour que le mode projet soit bien suivi par chacun.<br/><br/>Co-créez vos fiches de cadrage avec les chefs de projet sur AirSaas, pour les impliquer dès le départ, et diffuser une culture projet qui aligne chacune des parties prenantes de la transformation de l'entreprise.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d473f144eace1121240b18_Modal%20-%20create%20project.webp", "imageAlt": "Cadrage de projet dans votre logiciel PPM" }, { "type": "feature-split", "reversed": true, "title": "Réduisez les durées de vos projets dans le portefeuille", "body": "Votre challenge : faire en sorte qu’un projet ne dépasse jamais les trois mois. Voilà la clé pour dynamiser votre roadmap avec toutes vos parties prenantes, et vous aligner sur les besoins de l'entreprise, qui nécessite de plus en plus d'innovations et d'agilité.<br/><br/>Découpez en différentes phases vos \"gros\" projets, pour rendre votre processus de gestion de portfolio projet plus dynamique.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d73278ff90d9fe4f02eeb8_Portfolio%20project%20reminder%20late.webp", "imageAlt": "Reporting" }, { "type": "feature-split", "reversed": false, "title": "Marketez avec impact vos programmes de transformation", "body": "Bien communiquer les enjeux stratégiques liés à chacun de vos grands programmes est crucial pour motiver les différentes parties prenantes - et notamment les métiers et les équipes IT.<br/><br/>Donnez du sens à vos programmes dans la manière dont vous les formulez dans votre outil de portfolio management.", "imageAlt": "" }, { "type": "feature-split", "reversed": true, "title": "Ritualisez vos reportings", "body": "Votre reporting est l'élément-clé qui vous permet de prioriser, de fluidifier la prise de décision en Copil, mais aussi de motiver tous les acteurs de la transformation de votre entreprise au quotidien.<br/><br/>Gagnez du temps sur la création de vos reportings en utilisant un outil PPM qui automatise votre flash report, dans un format aisément compréhensible.<br/><br/>Puis envoyez ce reporting flash à toutes vos parties prenantes à intervalles réguliers, pour leur permettre de faire une revue de portefeuille projet claire, et de visualiser aisément les urgences et les risques en cours.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting" }, { "type": "feature-split", "reversed": false, "title": "Placez la transparence au coeur de votre portfolio project management", "body": "La transparence permet de générer de l'engagement de la part des différents acteurs de vos projets, et vous aide à les solliciter rapidement en cas d'urgence ou d'avancement à plat.<br/><br/>Facilitez l'accès de tout le monde aux différents jalons de vos projets et aux décisions qui sont prises, en centralisant tout sur une même plateforme qui permet d'avoir des vues personnalisables sur le portfolio de projets.<br/><br/>Sponsors, métiers, directions générales, chefs de projets : tout le monde a le même accès à la même information, pour être bien aligné autour des priorités et des besoins de chaque projet.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659c4b7b9b402047debe417c_portfolio4.svg", "imageAlt": "la transparence au coeur de votre portfolio" }] }, { "slug": "revue-de-portefeuille", "type": "solution", "meta": { "title": "l’outil de revue de portefeuille projets qui simplifie votre gouvernance", "description": "Fluidifier la préparation de vos revues de portefeuille de projets, avec un tableau de bord personnalisé et un reporting automatisé", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "L’outil de revue de portefeuille projets moderne qui simplifie votre gouvernance", "subtitle": "Parce que la revue de portefeuille est au cœur de votre process de transformation d’entreprise, AirSaas simplifie leur planification et leur préparation, en vous proposant des tableaux de bord consolidés et un reporting automatisé.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "6 clés pour rendre vos revues de portefeuille de projet plus efficaces", "body": "<p>Préparation, priorisation et arbitrage : voici les trois maîtres-mots d’une bonne revue de portefeuille projets. Prenez le temps d’appliquer les six bonnes pratiques suivantes à votre prochaine réunion, et observez-en les effets en termes d’efficacité.<br/></p>" }, { "type": "feature-split", "reversed": false, "title": "Vos données consolidées dans une seule plateforme", "body": "Grâce à AirSaas, visualisez toutes les données dont vous avez besoin pour préparer vos revues de portefeuille, sans avoir besoin d’aller les chercher à droite et à gauche.<br/><br/>Tout se trouve là, dans votre tableau de bord de gouvernance projet, consolidé et mis à jour par vos différents chefs de projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Des vues personnalisables pour mieux classifier vos projets", "body": "Sur AirSaas, visualisez vos projets en fonction de leur niveau de risque, de leur météo, ou encore de leur statut.<br/><br/>Une vue liste pour bien visualiser les indicateurs-clés des projets, une vue Kanban pour vous focaliser sur leur état d’avancement, et une vue timeline pour observer le tout sous forme de diagramme de Gantt. De quoi préparer votre revue de portefeuille en quelques clics.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Votre reporting flash automatisé", "body": "Parce que le <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">reporting</a> est un moment-phare de toute gestion de portefeuille de projets, automatisez-le grâce à AirSaas, pour vous focaliser sur le pilotage de vos programmes de transformation.<br/><br/>Vous gagnez ainsi du temps dans la préparation de votre revue de portefeuille, en consolidant toutes les données-clés dans un format hyper lisible, qui se focalise sur les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">jalons d'avancement des projets</a>, la météo, les risques, et les priorités.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Optimisation des ressources disponibles" }, { "type": "feature-split", "reversed": true, "title": "Une expérience utilisateur moderne et fluide", "body": "Les PMO et DSI qui nous ont aidé à concevoir AirSaas nous l’ont dit : bon nombre d’outils de gestion de portefeuille projets sont trop complexes, trop peu lisibles et personnalisables.<br/><br/>C’est pour répondre à ce souci qu’AirSaas est pensé pour simplifier sa prise en main et son utilisation au quotidien. Alignez chacune des parties prenantes de votre transformation d’entreprise sur la plateforme, et laissez le collaboratif vous aider à mener plus loin vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Collaborez lors de la création de vos fiches de cadrage de projet", "body": "Rassemblez vos chefs de projet et métiers dans votre logiciel de gestion de portfolio, pour co-créer avec eux les fiches de cadrage de vos projets. Homogénéisez et standardisez la culture projet de votre entreprise, et faites en sorte que chaque projet parte toujours sur le bon pied.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Générez vos bilans de projets en quelques clics", "body": "Un projet est finalisé ? Il est temps d’en faire le bilan auprès de vos différentes parties prenantes grâce à AirSaas. Visualisez aisément vos délais, l’engagement de vos équipes, vos budgets et coûts ainsi que les retours DAKI de chacun. De quoi motiver tout le monde, et les féliciter des beaux efforts accomplis.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Synchronisez vos outils préférés grâce à nos intégrations natives", "body": "Fini le temps passé à reporter à la main des informations d’une plateforme à une autre ! Sur la marketplace AirSaas, retrouvez des intégrations à vos outils de gestion de tâches préférés (Jira, Asana, ClickUp, Monday), à vos outils de communication (Microsoft Teams), ou à votre logiciel de service client (Zendesk).", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Prioriser les sujets à aborder", "body": "Appliquez une priorisation des sujets à aborder lors de votre revue en fonction de leur alignement par rapport aux objectifs stratégiques et organisationnels. L’idée ? Faire en sorte d'aborder les sujets les plus importants en premier - soit ceux qui apportent le plus de valeur à l'organisation, et qui sont les plus à risques au moment de la revue de portefeuille. Privilégiez le fait de retarder ou rejeter un projet à faible valeur ajoutée pour l'entreprise, plutôt qu'un projet-phare qui permet de lui donner un nouvel avantage concurrentiel ou une nouvelle innovation.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Inviter les bonnes personnes à votre revue de portefeuille", "body": "Invitez à vos revues de portefeuille de projets uniquement les personnes qui peuvent prendre des décisions et qui permettent d'éclairer le processus décisionnel. Vous pouvez ainsi focaliser l'attention sur le fait de faire avancer votre portfolio project management, et de resserrer les débats autour de l'essentiel. L'idéal ? Inviter le Codir, les sponsors des différents programmes (les directions), et éventuellement les gestionnaires des projets des projets à risques sur le moment.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": false, "title": "Envoyer votre reporting en amont", "body": "L’envoi en amont de votre flash report permet de fluidifier la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-decider-en-copil\">prise de décision</a> en revue de portefeuille, en alignant toutes les parties prenantes autour des mêmes informations. Vous pouvez alors piloter la réunion de manière plus efficace, plus fluide.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Adopter une structure claire pour votre revue de portfolio", "body": "Mettez toujours en place la même structure de présentation, et un ordre du jour bien structuré : état d'avancement des projets, achèvement des projets finalisés, décisions à venir, gestion des ressources nécessaire, et informations sur les nouveaux projets à venir. Votre flash report multi-projets doit lui-même toujours adopter le même format pour être vraiment efficace.", "imageAlt": "" }, { "type": "feature-split", "reversed": false, "title": "Ritualiser votre revue de portefeuille", "body": "Organisez vos revues à échéances fixes, en fonction des besoins de votre organisation. La plupart des PMO et DSI. font une revue de portefeuille de projets mensuelle. Organisez également cette revue après les autres types de réunions liées à votre gouvernance de portfolio de projets (après vos réunions d'avancement hebdomadaires avec les chefs de projets, et après votre réunion de coordination des ressources bi-mensuelle avec les chefs d'équipes. Ainsi, vous êtes sûr d'avoir toutes les informations nécessaires à la revue de portefeuille, et de présenter des métriques-clés bien à jour en temps réel.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66865ccd6319bebdceb619e4_Presentation-review-slide.png", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Aller au-delà des chiffres", "body": "Ne vous focalisez pas uniquement sur les métriques-clés liées à vos projets. Les chiffres parlent autant que les retours des équipes elles-mêmes - y compris du chef de projet en charge d'un projet spécifique. Dédiez toujours un temps de parole aux différents responsables, ou incluez à vos présentations des verbatims pour mobiliser l'attention des différents décideurs pendant la revue de portefeuille.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659ed24faa749ab95880701a_portfolio8.svg", "imageAlt": "Reporting projet" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "tableau-de-bord-dsi", "type": "solution", "meta": { "title": "Airsaas : le tableau de bord DSI nouvelle génération", "description": "Le tableau de bord DSI idéal pour piloter votre portefeuille de projets par la valeur, et accélérer la transformation de votre entreprise en fluidifiant la prise de décision", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Le tableau de bord que tous les DSI attendaient", "subtitle": "Le vieil adage disant “on ne peut pas améliorer ce que l’on ne mesure pas” s’applique particulièrement à la Direction des Systèmes d’Information. Avant même d’“améliorer”, “mesurer” permet d’éviter les glissements rapides, propres aux métiers de l’IT, ayant des forts impacts sur le client, interne ou externe (retards, surcoûts, etc.).La mesure et le suivi des indicateurs clés permettent ensuite les améliorations, les optimisations, la mise en place de stratégies de pilotage ambitieuses avec la Direction Générale.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "intro", "subSections": [{ "title": "Le pilotage par la valeur" }] }, { "type": "intro", "body": "<p>La clé de la réussite pour l’entreprise est de <strong>prioriser les investissements</strong> qui lui apporteront le plus de valeur. Le rôle du DSI est de mettre en place la <strong>gouvernance</strong> et les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">indicateurs</a> permettant de prendre les bonnes décisions afin d’optimiser le pilotage des projets à mener.</p><p>Pour cela, il faut pouvoir rassembler les membres de direction autour d’un tableau de bord DSI présentant les données essentielles des différentes activités afin d’être <strong>efficace dans la prise de décision</strong>.</p><p>Les indicateurs principaux se rassemblent en 3 domaines :</p><ul><li>Domaine de la planification et de l’avancée des projets</li><li>Domaine du pilotage des ressources</li><li>Domaine du suivi des budgets</li></ul>" }, { "type": "intro", "body": "<p>La vue Kaban est plutôt dédiée à l’observation de la répartition des projets en fonction des états d’avancement. Elle permet souvent de sentir des tendances (beaucoup de projets en attente de validation, trop de projets en cours en parallèle, etc.) et d’ainsi optimiser le pilotage de la performance.</p>" }, { "type": "intro", "title": "Toutes les directions avaient leurs tableaux de bord - maintenant, vous aussi", "body": "<p>Vous n’avez pas attendu AirSaas pour vous constituer votre propre tableau de bord de la DSI, et vous avez raison. A la suite d’audits de plusieurs dizaines de DSI, nous avons développé un tableau de bord de pilotage pour les DSI.<br/></p>" }, { "type": "intro", "title": "Pourquoi utiliser un tableau de bord est essentiel pour le pilotage d’un système d’information ?", "body": "<p>Si les DSI étaient auparavant centrées principalement sur des problématiques techniques, elles deviennent de plus en plus orientées business : le pilotage du système d’information est maintenant considéré dans une entreprise comme un levier important de création de valeur. <br/>‍<br/>Mais si elle souhaite être en capacité d’aider son entreprise à atteindre ses objectifs business, le pilotage de la DSI doit être optimal. Et c’est là qu’un tableau de bord prospectif devient indispensable à la bonne gouvernance du système d’information.<br/><br/>En effet, si une organisation veut évoluer, elle doit forcément se donner les moyens de s’évaluer. Sinon, comment savoir si elle progresse et atteint ses objectifs ? <br/>Ainsi le tableau de bord prospectif est l’outil qui permet à la DSI de s’assurer un pilotage efficace au travers d’objectifs à court, moyen et long terme. Le but du tableau de bord prospectif est d’assurer que les buts seront atteints sans être entravés par une problématique d’ordre opérationnelle, ou organisationnelle.</p><p>Pour synthétiser, un tableau de bord de la DSI permet de :</p><ul><li>Assurer le pilotage optimal de la DSI</li><li>Instaurer une communication interne efficace</li><li>Repérer les tendances au sein de l’entreprise</li><li>Assurer la gestion du suivi dans le temps de chaque objectif</li><li>Analyser les écarts entre les objectifs fixés et ceux atteints</li><li>Responsabiliser chacun des collaborateurs en leur assignant la gestion d’objectifs</li></ul>" }, { "type": "intro", "title": "L’importance des indicateurs choisis pour assurer un pilotage optimal du système d’information" }, { "type": "intro", "body": "<p>En effet, ce sont les indicateurs de performance issus du monde industriel qui ont été transposés dans les tableaux de bord afin d’analyser l’activité des DSI. Cependant, ces indicateurs traditionnels de pilotage (comprenant la comptabilité ou encore le contrôle budgétaire) ne sont pas du tout adaptés à l’élaboration d’un tableau de bord de la maintenance du système d’information qui assure le suivi d’activités qui, par nature, sont transverses. A l’inverse, ces indicateurs du monde industriel ont été pensés dans une logique de contrôle des coûts : ils visent à découper chaque service opérationnel en unités plus petites, afin de connaître le coût que chacune de ces unités occasionne et, ainsi, pouvoir penser des méthodes pour réduire ces mêmes coûts. <br/>‍<br/>Ainsi, la transposition de ces indicateurs dans les tableaux de bord a été néfaste à l’évaluation des activités relatives au pilotage du système d’information. Elle a d’ailleurs impacté la manière dont sont perçues les DSI dans les entreprises et dans de nombreux articles.<br/></p><ul><li>Les aspects technologiques et financiers des DSI étaient correctement évalués par ces indicateurs de performance dans les tableaux de bords, mais ils se révélaient incapables de traiter les informations relatives à la communication, aux collaborateurs ou encore à au pilotage de la stratégie de l’entreprise.</li><li>Les informations traitées par ces indicateurs concernent le passé et le présent, mais très rarement le futur. Ces tableaux de bords sont donc bien plus proches d’un simple rapport d’activités que d’un véritable outil de pilotage de la performance !</li></ul><p>Ainsi, il n’est pas rare que les informations données par les tableaux de bord de la DSI ne reflètent pas vraiment son activité dans sa globalité, mais soient essentiellement axés sur le contrôle des budgets et le pilotage des technologies.</p>" }, { "type": "intro", "body": "<p>A titre d’exemple : il a été constaté qu’une large majorité des tableaux de bord des DSI incorporent une notion de budget, alors que seulement 20% d’entre elles ont mis en place des indicateurs afin d’évaluer la valeur produite par la DSI !<br/>Dès lors, on comprend que les SI soient majoritairement perçus comme des centres de coûts et non de valeur. Et si les entreprises se sont habituées à centrer leurs tableaux de bord sur les coûts plutôt que sur la valeur, c’est en partie parce que ce sont les systèmes de gestion industriels qui ont été transposés, mais aussi parce qu’inventer des indicateurs permettant de mesurer la valeur produite pas une DSI est complexe !<br/>Cette vision de la Direction des Systèmes d’Information par le prisme des coûts plutôt que par celui de la valeur est ainsi majoritairement représenté dans les Directions Générales des entreprises, ce qui impacte forcément fortement la prise de décision en matière de transformation digitale.</p>" }, { "type": "intro", "body": "<p>Parmi les usages principaux du tableau de bord de la direction :<br/></p><ul><li>Quel est le coût total de l’informatique dans l’entreprise ?</li><li>Les ressources sont-elles engagées sur les projets apportant le plus de valeur ?</li><li>A quel point l’informatique apporte de la valeur aux différents métiers et à la performance globale de l’entreprise ?</li><li>Où se situe la performance des SI par rapport à la concurrence ?</li><li>Quels sont les futurs projets sur lesquels investir ?</li></ul><p>Plusieurs de ces questions sont orientées vers les coûts de la DSI pour l’entreprise (qui représentent en moyenne entre 1% et 5% du budget total de l'entreprise en fonction des secteurs), mais plusieurs d'entre elles requièrent des indicateurs centrés sur la valeur produite par la DSI.<br/><br/>Pourtant, de nombreux tableaux de bord soumis aux directions générales se réduisent à une analyse de la dimension budgétaire des DSI. Ainsi, en se penchant sur les tableaux de bord, un grand nombre de DG se retrouve face à une solution de facilité : juger les performances de la DSI en fonction du rapport entre le budget que coûte l’informatique et le chiffre d'affaires de l'entreprise.<br/><br/>L’objectif de performance principal devient donc de ne pas trop dépenser - alors même qu’il est évident que la performance d’une DSI ne peut pas être évaluée par sa simple capacité à respecter les budgets. <br/>‍<br/>Pire : il peut être tentant pour des DG de comparer le budget dépensé par leur entreprise pour leurs systèmes d'informations aux sommes investies par des entreprises concurrentes. Mais il a été démontré que chaque entreprise ne délimite pas les sommes qui doivent être considérées comme investies par la DSI en se basant sur les mêmes principes ! De plus, en fonction des secteurs, les besoins de digitalisation ne sont pas du tout semblables.<br/><br/>Ainsi, essayer de se comparer à ses concurrents par le prisme budgétaire est un piège pour les DG. <br/><br/>Les Directions Générales doivent donc inciter les DSI à créer des indicateurs de tableau de bord prospectif permettant de mesurer leur performance en fonction de la valeur créée par rapport aux intérêts stratégiques de l’entreprise. Les Directions Générales n’ayant pas compris l’importance d’optimiser les indicateurs du tableau de bord prospectif pour peser dans la stratégie globale de l'entreprise prennent, eux, du retard sur leurs concurrents.</p>" }, { "type": "intro", "title": "Comment construire des indicateurs du tableau de bord pertinents ?" }, { "type": "intro", "body": "<ul><li>Tous les indicateurs du tableau de bord informatique de la Direction des Systèmes d’Informations doivent être nommés</li><li>Tous les indicateurs du tableau de bord informatique de la DSI doivent être définis et la définition doit être connu par tous</li><li>Chaque indicateur du tableau de bord informatique de la Direction des Systèmes d’Informations doit être assorti d’un objectif : sans, il devient inutile</li><li>Les indicateurs du tableau de bord informatique de la Direction doivent prendre en compte, le passé, le présent mais aussi le futur</li><li>Pensez à construire des indicateurs de tableau de bord évaluant des résultats (statiques) mais aussi des processus (dynamiques)</li><li>Construisez vos indicateurs de tableau de bord des études de vos activités afin qu’ils puissent être comparables entre eux</li><li>Indiquez la fréquence de mise à jour de l’indicateur de tableau de bord (annuelle / trimestrielle / mensuelle / journalière…)</li></ul>" }, { "type": "intro", "subSections": [{ "title": "Penser les indicateurs de tableau de bord comme le reflet des objectifs de l’entreprise", "body": "<p>Bien qu’on puisse trouver des tableaux de bords avec des indicateurs de performance déjà pensés et prévus pour pouvoir s’appliquer à toute entreprise, la solution optimale est d’opter pour la personnalisation.</p>" }] }, { "type": "intro", "body": "<p>Chaque tableau de bord servant au pilotage d’une DSI doit être construit au regard des objectifs de l’entreprise : ces derniers doivent refléter ses ambitions stratégiques.</p><p>Chaque organisation possède un fonctionnement spécifique, un tableau de bord informatique générique aura donc une efficacité limitée. Ainsi, les tableaux de bord les plus efficaces sont ceux qui décrivent le pilotage des systèmes d’information au regard du contexte de leur entreprise.</p><p>Un tableau de bord informatique est donc complexe à construire et requiert de prendre du recul sur les activités de l’entreprise : l’une des meilleures méthodes pour arriver à un tableau de bord représentatif du réel est d’impliquer les directions métiers dans sa conception.</p>" }, { "type": "intro", "body": "<p>Impliquer les métiers dans l'élaboration des tableaux de bord est indispensable pour faire coller les indicateurs à la situation réelle de l’entreprise. L’idéal est de former des équipes constituées de responsables métiers (si possible volontaires) et accompagnées par des membres des équipes de la DSI. Ainsi, les responsables métiers pourront indiquer les axes qui leurs apportent le plus de valeur et qui leurs semblent donc le plus pertinent d’évaluer et de suivre régulièrement grâce au tableau de bord. <br/>‍<br/><strong>Pour résumer,</strong> construisez vos indicateurs de tableaux de bord :</p><ul><li>en respectant des principes de forme, afin qu’ils soient réellement exploitables</li><li>en les adaptant aux objectifs spécifiques de votre entreprise</li><li>en impliquant les directions métiers dans leur élaboration</li></ul><p>Si vous suivez ces principes, vous aurez de bonnes chances d’aboutir à un tableau de bord permettant réellement de piloter votre DSI de manière optimale.</p>" }, { "type": "feature-split", "reversed": false, "title": "Pour la planification, AirSaas propose trois vues ayant chacune une utilité différente", "body": "La vue liste permet, pour un état d’avancement donné, de <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-gestion-de-projet\">passer en revue les projets</a> avec tous les indicateurs au premier plan. Quelles sont les actions à prendre pour faire passer ces projets à l’état suivant ?", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Des vues différentes pour mieux piloter les projets" }, { "type": "feature-split", "reversed": true, "title": "Embarquez par une bonne communication", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Le rapport flash automatisé", "body": "Le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">reporting</a> est essentiel. Il est malgré tout chronophage et souvent délaissé. Nous vous donnons la possibilité de générer des <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">rapports flash</a> en un clic. Exportables en PDF ou en PowerPoint, vous pouvez ainsi tenir au courant les parties prenantes de l’avancée de vos activités. <br/>Le rapport flash rassemble les projets sur lesquels vous souhaitez communiquer. Pour chacun d’entre eux, deux slides sont générées : une slide de rappel des informations de cadrage, et une contenant les éléments clés de l’exécution.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash" }, { "type": "feature-split", "reversed": true, "title": "Suivi de l’indicateur d’adhésion", "body": "Nous mettons à disposition un outil de sondage anonyme de confiance des parties prenantes dans l’adhésion du projet en cours. Plus ce degré de confiance est élevé, plus votre projet aura de chance d’être un succès. Au contraire s’il est faible, il faut agir vite. Rien de pire qu’un projet terminé mais ne correspondant pas au besoin du client.<br/>En un clic, envoyez le sondage à toutes les personnes intervenant sur le projet. Faites-le à intervalle régulier et évitez les mauvaises surprises dans le pilotage de vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd67b20f0e6f_dashboard.svg", "imageAlt": "Sondage collaborateur" }, { "type": "feature-split", "reversed": false, "title": "Devenez un centre de profit plutôt qu’un centre de coût", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Transformer la DSI" }, { "type": "feature-split", "reversed": false, "title": "Des données consolidées", "body": "Souvent mise en place sur Excel ou sur des outils de visualisation, les tableaux de bord que nous avons pu observer ne disposent pas d’une donnée consolidée. AirSaas se connecte aux différents outils de gestion de projet et vous propose une abstraction. La donnée est consolidée autours des projets, des solutions partenaires, des équipes impliquées, etc. pour vous permettre d’afficher et de suivre les indicateurs indispensables au pilotage de votre activité.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd35ed0f0e71_1.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Des indicateurs intelligents d’aide à la décision", "body": "L’objectif ici est d’apporter des éléments d’attention aux DSI afin de leur simplifier la prise de décision. Par exemple, lorsqu'un projet nécessite une prise de décision depuis plusieurs semaines alors qu’il est stratégique pour une direction métier, il est important d’en être informé pour optimiser le pilotage de la performance de sa DSI.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd17cf0f0e87_2.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Simple et collaboratif by design", "body": "Il est essentiel d’impliquer les équipes dans cette démarche. Pour cela il faut un outil simple, ne nécessitant pas de formation et permettant de travailler ensemble en fonction des droits d’accès de chacun. AirSaas a été conçu comme point de rencontre entre la DSI et les directions métiers.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fdde5c0f0e46_outil4.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "La transposition infortune des systèmes traditionnels de gestion aux tableaux de bord des DSI", "body": "Comme l’expliquent Philippe Rosé et Christophe Legrenzi dans leur ouvrage “Les tableaux de bord de la DSI”, les systèmes d’information ont pendant longtemps été évalués grâce à des tableaux de bord et des indicateurs qui n’étaient pas adaptés à l’analyse du pilotage d’une DSI.<br/>‍", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd06800f0e86_3.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "D’un tableau de bord centre de coûts à un tableau de bord centre de profit", "body": "Cette manière d’évaluer les performances de la DSI a forcément amené les entreprises à analyser les systèmes d’information en fonction de ce qu’ils coûtent. Conséquence : le pilotage des systèmes d’information via les tableaux de bord se fait principalement par les coûts et non par la valeur qu’ils peuvent apporter.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4d920f0e88_7105959688182da7475c8681c14e857d_4.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Le tableau de bord de la DSI au service de la direction générale", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Des principes à respecter dans la construction des indicateurs d’un tableau de bord", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Penser les indicateurs de tableau de bord comme le reflet des objectifs de l’entreprise", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": false, "title": "Impliquer les métiers dans la fabrication des indicateurs du tableau de bord informatique", "body": "", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Pilotage de projet" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "tableau-de-bord-gestion-de-projet", "type": "solution", "meta": { "title": "Airsaas : le tableau de bord de gestion de projet conçu pour les DSI", "description": "Une solution PPM moderne qui vous donne accès à un tableau de bord de gestion de projet compréhensif et intuitif, pour faciliter le suivi et le reporting projet", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Le tableau de bord de gestion de projet moderne", "subtitle": "Comme tout organe de direction, la DSI a un besoin constant de mesurer son activité : c’est seulement de cette manière qu’elle est à même d’optimiser chacun de ses processus de gestion de projet et de réduire le nombre de dérapages avec des conséquences négatives fortes pour le client (dépassement des coûts, des délais de livraisons des projets…). Pour vous aider, nous avons conçu le grand guide de la conduite de projet.‍Mesurer ses performances grâce à des indicateurs permet ainsi de calibrer les changements à implémenter afin d’augmenter la productivité de ses services et de pouvoir exécuter des projets encore plus ambitieux. La mesure et le suivi des indicateurs clés permettent ensuite les améliorations, les optimisations, la mise en place de stratégies de pilotage ambitieuses avec la direction générale.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "intro", "body": "<p>Une des clés pour assurer la pérennité de son entreprise est de savoir hiérarchiser les projets afin de prioriser ceux qui crééront le plus de valeur. Si elle veut être performante, la DSI doit créer des <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">indicateurs</a> qui permettront à la direction de prendre les meilleures décisions et d’assurer un pilotage optimal des projets IT. <br/>Pour cela il faut être en capacité d’informer efficacement les membres du board. L'<a href=\"https://www.airsaas.io/fr/solution/outils-de-pilotage-projet\">outil idéal</a> pour cela est un tableau de bord gestion de projet possédant des indicateurs offrant une visibilité sur trois des domaines principaux :</p><ul><li>La planification et le suivi de chaque projet</li><li>Le suivi des ressources disponibles</li><li>La gestion des budgets</li></ul>" }, { "type": "intro", "body": "<p>Vous avez la possibilité de filtrer ces vues en fonction de différents indicateurs : leur importance métier, la météo du projet, les équipes qui travaillent dessus, les objectifs qui y sont assignés...<br/><br/>AirSaas simplifie ainsi la gestion de vos ressources et budgets : vous pouvez créer différents scénarios, projeter l’exécution de plusieurs projets, et ainsi observer leur impact sur votre performance. <br/>‍<br/>De cette manière, vous pouvez répartir votre force de travail de manière optimale.</p>" }, { "type": "intro", "body": "<p>Si une DSI souhaite accompagner le développement de son entreprise, elle doit diriger l’exécution de ses projets de manière optimale. Et justement, le tableau de bord de gestion de projet se révèle très vite être indispensable à un pilotage efficient d’une DSI.<br/>‍<br/>Si l’on désire améliorer ses process, il faut d’abord être capable d’évaluer ses pratiques actuelles : c’est la meilleure manière pour savoir si les méthodes mises en place sont efficaces et permettent d’atteindre les objectifs fixés. Un <a href=\"/fr/solution/tableau-de-bord-dsi\">tableau de bord</a> projet permet donc d’assurer le pilotage des aspects opérationnels des projets IT, à court comme à long terme, mais aussi :</p><ul><li>à assurer l’exécution optimale de chaque projet</li><li>à structurer une communication interne performante</li><li>à analyser les tendances grâce à une visibilité sur l’ensemble des projets</li><li>à suivre les avancées de chaque projet au regard des objectifs fixés</li><li>à impliquer les collaborateurs en leur affectant à chacun des objectifs</li></ul>" }, { "type": "intro", "title": "Comment choisir les indicateurs appropriés pour son tableau de bord projet ?" }, { "type": "intro", "body": "<ul><li>Il est indispensable de nommer chacun des indicateurs</li><li>Il faut aussi définir chaque indicateur, et s’assurer que chaque collaborateur utilise la même définition</li><li>Il faut assortir chaque indicateur d’un objectif, si possible chiffré : à défaut, ils perdent presque tout intérêt</li><li>Les indicateurs doivent analyser le passé, le présent, mais aussi les évènements à venir : ils ne servent pas seulement à rapporter, mais bien à piloter</li><li>Les indicateurs construits autours de processus (dynamiques) sont tout aussi importants que ceux qui évaluent des résultats (statiques) : ne vous cantonnez pas à l’un de ces deux types</li><li>Pensez vos indicateurs de sorte qu’ils puissent être comparés entre eux lorsque c’est possible.</li><li>Rappeler la fréquence à laquelle votre indicateur devra être mis à jour (semestrielle/mensuelle/hebdomadaire).</li></ul>" }, { "type": "intro", "body": "<p>Chaque entreprise a des objectifs différents, et des caractéristiques qui lui sont propres : aussi, utiliser un template de tableau de bord universel ne peut avoir qu’une efficacité réduite. A l’inverse, un tableau de bord de gestion de projet dont les indicateurs ont été pensés en fonction des ambitions d’une entreprise sera forcément plus performant pour accompagner le pilotage d’une DSI. <br/><br/>Mais construire des critères en prenant en compte le contexte de l’entreprise (ses collaborateurs, les projets menés, les résultats que l’on souhaite atteindre) prend beaucoup de temps et est complexe. En effet, il faut une connaissance poussée de chacune des activités de l’organisation. Ainsi, il est fortement conseillé d’engager les directions métiers dans l’élaboration du tableau de bord et de ses indicateurs.</p>" }, { "type": "intro", "body": "<p>Engager les directions métiers dans la construction et la mise en œuvre des indicateurs de vos tableaux de bord vous permet de juger de l’avancée de vos projets selon les critères qui importent au client final. C’est donc la meilleure manière de contrôler que le produit livré offre une pleine satisfaction à ses utilisateurs.<br/><br/>Il est donc conseillé de créer ces indicateurs en formant des groupes de travail regroupant des responsables métiers ainsi que des membres de votre DSI.</p>" }, { "type": "intro", "title": "En conclusion, voici les deux règles principales à respecter pour élaborer des indicateurs de tableaux de bord qui boosteront vos performances :" }, { "type": "intro", "body": "<p>L’importance de l’innovation ne cesse de s’accroitre pour les entreprises : les projets digitaux se multiplient et leur réussite deviennent une condition sine qua none à la compétitivité de l’organisation. En conséquence, les entreprises ont de plus en plus d’attentes envers les DSI, qui se retrouvent souvent au coeur des nouvelles stratégies mises en place.</p><p>‍<br/>Notre tableau de bord projet a été créé afin de permettre à la DSI d’être en capacité de répondre aux besoins de son entreprise et de collaborer étroitement avec les métiers.</p><ul><li>Pensez-les au regard des caractéristiques propres de votre entreprise<br/></li><li>Co-construisez les avec des responsables métiers impliqués</li></ul><p>En suivant ces principes, vous maximisez vos chances de créer un tableau de bord simplifiant véritablement le pilotage de votre DSI.</p>" }, { "type": "feature-split", "reversed": false, "title": "AirSaas propose 3 vues pour offrir une visibilité totale sur vos projets :", "body": "Un suivi de l’avancée de chacun de vos projets, avec les indicateurs les plus importants. Ainsi vous savez constamment quelle est la prochaine étape pour faire évoluer vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Portfolio projects list" }, { "type": "feature-split", "reversed": true, "title": "Impliquez toutes les parties prenantes", "body": "L’objectif suprême est de parvenir à livrer un projet qui satisfait parfaitement votre client tout en respectant les délais prévus. Un des facteurs principaux pour y parvenir est d’impliquer votre client dès la phase du cadrage, et tout au long de l’exécution du projet. <br/><br/>De même, vous devez aussi être constamment en capacité d’informer votre direction de l’avancée ainsi que de l’état de tous vos projets, afin de lui permettre de <a href=\"/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">piloter au mieux l’entreprise</a>. <br/><br/>Nous avons créé deux outils pour vous aider à atteindre ces objectifs.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Impliquez toutes les parties prenantes" }, { "type": "feature-split", "reversed": false, "title": "Le rapport flash automatisé", "body": "Si le reporting est indispensable au bon déroulement d’un projet, il reste trop souvent délaissé, notamment parce qu’il requiert énormément de temps. C'est pourquoi nous vous offrons la possibilité de générer automatiquement des rapports flash. Exportables au format PDF ou PowerPoint, ils vous permettent de communiquer sur vos avancées à l’ensemble des parties impliquées dans vos projets.<br/>‍<br/><a href=\"/fr/solution/rapport-flash\">Le rapport flash</a> est composé de deux slides : l’une rappelle toutes les informations de cadrage, tandis que l’autre comporte toutes les informations nécessaires à la bonne exécution du projet.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash automatique" }, { "type": "feature-split", "reversed": true, "title": "Sondez vos collaborateurs grâce à l’indicateur d’adhésion", "body": "Les chances de succès d’un projet augmentent lorsque ses parties prenantes ont confiance dans son exécution. Nous avons créé un outil de sondage anonyme afin que vous puissiez connaître le degré de confiance de chacune des parties dans vos projets. Ainsi, vous aurez les capacités de réagir à temps afin d’éviter de livrer un produit trop éloigné des attentes de votre client. <br/>‍<br/>Vous pouvez envoyez ce sondage à toutes les personnes impliquées sur votre projet en moins d’une minute. Sonder régulièrement leur degré de confiance vous permettra d’assurer un résultat à la hauteur des espérances de chacun.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd67b20f0e6f_dashboard.svg", "imageAlt": "Sondage collaborateurs" }, { "type": "feature-split", "reversed": false, "title": "Tableau de bord de gestion de projets : pourquoi est-ce crucial pour une direction des systèmes d’information ?", "body": "A mesure que le digital se développe, les DSI sont de plus en plus amenées à se voir confier des missions touchant au coeur du business de leur entreprise : le système d’information est aujourd’hui considéré comme un des facteurs clés de la création de valeur.<br/>‍", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Tableau de bord de gestion de projet" }, { "type": "feature-split", "reversed": false, "title": "Quelques principes à respecter pour une gestion de portefeuille optimale", "body": "Il est important de respecter certaines règles de forme lors de l’élaboration des indicateurs, afin de s’assurer qu’ils soient pertinents :", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66867e827c10da64f5ea6d52_Graphic%20IT.svg", "imageAlt": "gestion de portefeuille optimale" }, { "type": "feature-split", "reversed": true, "title": "Construisez les indicateurs de tableau de bord projet en fonction des ambitions de votre organisation", "body": "Il existe des tableaux de bord dont le choix des indicateurs pertinents est déjà pensé, et qui ont pour vocation d’être capable de s’adapter à toutes, ou au moins, à un grand nombre d’entreprises. Cependant, prendre le temps d’élaborer des indicateurs personnalisés à son organisation reste la meilleure solution.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Vos indicateurs de tableau de bord projet" }, { "type": "feature-split", "reversed": false, "title": "Engager les métiers dans la fabrication des indicateurs du tableau de bord", "body": "Il n’est pas rare que les directions métiers ne soient que très peu sollicitées dans l’élaboration des tableaux de bord des DSI. Pourtant, ce sont bien les métiers qui sont les destinataires et les utilisateurs de la grande majorité des solutions sur lesquelles travaillent les équipes IT !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd42890f0e53_outil12.svg", "imageAlt": "Engagez les métiers dans la construction des indicateurs" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Adoptez dès maintenant une solution efficace de flash report projet", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "tableau-de-bord-portefeuille-de-projet", "type": "solution", "meta": { "title": "Le tableau de bord de portefeuille de projet collaboratif et moderne", "description": "Rendez votre portfolio management plus simple au quotidien grâce au tableau de bord de portefeuille de projet moderne, basé sur la collaboration : AirSaas.", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Le tableau de bord de portefeuille de projet collaboratif et moderne", "subtitle": "En matière de portfolio project management, chaque entreprise présente des besoins différents. C’est pour satisfaire ces besoins qu’AirSaas a développé un tableau de bord de portefeuille de projet personnalisable, à l’expérience utilisateur fluide, qui fluidifie la gouvernance des programmes de transformation au quotidien.", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "logo-bar", "title": "Ils parlent de nous", "variant": "press", "logos": [{ "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10687150c6042f155dcd4_logo-alliancy-monotone.png", "alt": "Alliancy" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d106ab9c5e18b386c84505_JDN-monotone.png", "alt": "JDN Journal du NET" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/63d10458acb275dbac3ecb65_LePoint-monotone.png", "alt": "Le Point" }, { "src": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/64141ec10a541a09487cd1ec_LMI.png", "alt": "lemondeinformatique.fr" }] }, { "type": "intro", "title": "Collaborez pour mieux transformer", "body": "<p>Grâce à AirSaas, vous n’êtes plus seul dans votre portfolio management. Vos chefs de projets et métiers vous aident très aisément, en vous aidant à cadrer vos projets en amont, et en vous indiquant les changements à l'œuvre sur leurs projets au quotidien. Tout le monde est informé, et votre transformation d’entreprise va plus vite, plus loin.<br/></p>" }, { "type": "intro", "title": "Les clés de succès pour concevoir votre tableau de bord de gouvernance projet", "body": "<p>Bon nombre de PMO ou de DSI choisissent de partir d’un modèle de tableau de bord de portefeuille de projet pour concevoir le leur. Cependant, la meilleure pratique consiste à créer le vôtre propre, grâce à l’aide d’un outil PPM performant. Suivez ces règles d’or pour faire en sorte que vos tableaux de bord suivent et boostent vraiment votre performance.<br/></p>" }, { "type": "feature-split", "reversed": true, "title": "Une vue macro au service de votre planification stratégique", "body": "Si AirSaas est le tableau de bord de portefeuille projet préféré de bon nombre de PMO et DSI, c’est parce qu’il permet de bénéficier d’une vue macro de l’ensemble des projets qu’ils gèrent.<br/><br/>Sur la plateforme, toutes les informations-clés dont vous avez besoin sont rassemblées et consolidées, toujours à jour. Cette vue exhaustive vous fait prendre de la hauteur, et vous aide à <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">prendre les meilleures décisions</a>, en fonction des priorités stratégiques de votre organisation.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "planification stratégique" }, { "type": "feature-split", "reversed": false, "title": "Pas besoin de reporter vos données à la main grâce aux intégrations natives", "body": "La marketplace d’intégrations natives d’AirSaas facilite la mise à jour de vos tableaux de bord de gestion de projets, en évitant le report de données à la main.<br/><br/>Vous y trouverez des intégrations à vos outils de gestion de tâches préférés (Jira, Asana, ClickUp, Monday), à vos outils de communication interne (Microsoft Teams), ou à votre logiciel de service client (Zendesk).", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives" }, { "type": "feature-split", "reversed": false, "title": "La vue liste", "body": "Elle vous permet de suivre l’avancée de chacun de vos projets et des indicateurs qui y sont liés. Passez en revue vos projets pour savoir à tout moment où vous en êtes, et comment faire évoluer vos projets vers la prochaine étape.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "List" }, { "type": "feature-split", "reversed": true, "title": "La vue Kanban", "body": "Besoin de repérer des tendances générales dans votre portefeuille de projets ? Passez en vue Kanban, et observez les états d’avancement de vos projets pour optimiser votre stratégie de pilotage.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Kanban" }, { "type": "feature-split", "reversed": false, "title": "La vue timeline", "body": "Sous forme de diagramme de Gantt, elle vous permet d’organiser vos projets sur le temps long. Repérez à l’avance les surcharges en termes de gestion des ressources et les dépendances inter-projets, et anticipez les retards.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Timeline" }, { "type": "feature-split", "reversed": false, "title": "Un flash report pour fluidifier la prise de décision", "body": "Le reporting flash automatisé d’AirSaas permet à vos différentes parties prenantes (décisionnaires, sponsors, chefs d’équipe et de projet…) de comprendre quelles décisions doivent être prises sur le moment.<br/><br/>Sa structure rappelle les grandes lignes des projets (planning, timeline, indicateurs-clés…) pour ensuite rentrer dans le détails des projets urgents. Jalons, statuts, risques et météos des projets, métriques d’avancée, gains attendus, ressources humaines et budgets impliqués : tout s’y trouve pour faciliter votre prise de décision.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions" }, { "type": "feature-split", "reversed": true, "title": "Une structure bien huilée et personnalisable", "body": "Le flash report d’AirSaas se crée en un clic au format .ppt ou .pdf, dans une structure aisément lisible. Vous pouvez personnaliser le design de votre présentation aux couleurs de votre entreprise, et décider d’y ajouter des métriques-clés supplémentaires, un récapitulatif des décisions à prendre, ou encore des précisions sur les plannings de vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting projet" }, { "type": "feature-split", "reversed": true, "title": "Co-créez vos fiches de cadrage", "body": "Sur AirSaas, créez les fiches de cadrage de vos projets en mode collaboratif, sur une structure fixe qui standardise votre culture projet. Les chefs de projet remplissent ces fiches grâce à une méthodologie forte - pour qu’aucun projet ne commence jamais sur le mauvais pied.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage" }, { "type": "feature-split", "reversed": false, "title": "Communiquez aisément avec toutes vos parties prenantes", "body": "Depuis AirSaas, paramétrez les notifications que vous envoyez à vos équipes opérationnelles lorsqu’un projet est à risque. Vous pouvez également envoyer automatiquement des bilans de la période, paramétrables à échéances fixes sur la plateforme.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Communiquez" }, { "type": "feature-split", "reversed": true, "title": "Partagez vos bilans de projet pour motiver tout le monde", "body": "Quand un projet se termine, il est temps d’en tirer les bonnes pratiques et ce qui peut être amélioré en matière de gestion de projet. Engagez vos différentes parties prenantes grâce aux bilans de projets AirSaas, que vous concevez automatiquement via la plateforme.<br/><br/>Analysez les coûts, les délais, l’engagement de vos équipes et leurs retours DAKI, et félicitez chacun pour les efforts accomplis - et ceux à venir !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "bilans de projet" }, { "type": "feature-split", "reversed": false, "title": "Choisissez bien vos indicateurs de performance", "body": "Les indicateurs que vous intégrez à votre tableau de bord de portefeuille de projet doivent à la fois analyser le passé, le présent, et les événements à venir dans votre portfolio. Il sont à la fois des outils de reporting, et des clés pour piloter votre gouvernance.<br/><br/>Construisez vos indicateurs à la fois autour de vos processus (KPI dynamiques) et de vos résultats (KPI statiques). Veillez également à ce qu’ils soient comparables entre eux lorsque cela est possible.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010195cd30eca1a1bd8bb_outil10.svg", "imageAlt": "indicateurs de performance" }, { "type": "feature-split", "reversed": true, "title": "Construisez les KPI de votre tableau de bord en fonction de vos besoins", "body": "S’il est tentant de partir d’un template de tableau de bord universel, il est crucial d’adapter les indicateurs qui s’y trouvent aux ambitions et besoins de votre entreprise. Il s’agit d’un élément essentiel pour assurer le pilotage de votre DSI.<br/><br/>Prenez en compte le contexte de votre entreprise (collaborateurs, projets menés, résultats escomptés), ainsi que ce que vous savez de chacune de ses activités.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "les KPI" }, { "type": "feature-split", "reversed": false, "title": "Co-construisez vos tableaux de bord avec les métiers", "body": "Pour obtenir un tableau de bord de portfolio management personnalisé, impliquez les directions métiers dans son élaboration. Après tout, ce sont eux les destinataires et utilisateurs des solutions que vos projets développent !<br/><br/>Créez vos indicateurs dans des groupes de travail qui rassemblent responsables métiers et membres de votre DSI. C’est là le gage d’un tableau de bord bien ficelé, et de livrables adaptés aux attentes de leurs utilisateurs finaux.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010238635278f1f6cecf1_outil12.svg", "imageAlt": "les métiers" }, { "type": "feature-split", "reversed": true, "title": "Rendez vos indicateurs limpides pour tous", "body": "Un bon tableau de bord de portefeuille de projet doit être aisément lisible par l’ensemble de vos parties prenantes.<br/><br/>Veillez donc à nommer chacun de vos indicateurs, et à les définir pour vous assurer que chacun utilise la même définition. Si possible, liez à chaque indicateur un objectif chiffré. Et n’oubliez pas de définir la fréquence à laquelle votre indicateur doit être mis à jour : semestrielle, mensuelle, ou hebdomadaire.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d73abfdd38dac29b4e219c_Project%20page%20zoom%20weather.webp", "imageAlt": "Project page zoom weather" }, { "type": "cta", "title": "Prêt à passer à l'action ?", "subtitle": "Choisissez un outil PPM collaboratif et moderne, qui simplifie vos prises de décisions et booste votre reporting.", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }] as const;

export const PAGES_BY_SLUG: Record<string, LandingPage> =
  Object.fromEntries(PAGES.map((p) => [p.slug, p]));
